CREATE DEFINER=`root`@`localhost` PROCEDURE `add_students_to_class` (IN `p_stream_id` INT, IN `p_class_prefix` VARCHAR(10), IN `p_count` INT)   BEGIN
    DECLARE i INT DEFAULT 1;
    DECLARE v_admission_no VARCHAR(20);
    DECLARE v_first_name VARCHAR(50);
    DECLARE v_last_name VARCHAR(50);
    DECLARE v_gender VARCHAR(10);
    DECLARE v_dob DATE;
    
    WHILE i <= p_count DO
        
        SET v_admission_no = CONCAT('KWA-2026-', p_class_prefix, '-', LPAD(i, 3, '0'));
        
        
        SET v_gender = IF(RAND() < 0.5, 'male', 'female');
        
        
        SET v_first_name = ELT(FLOOR(1 + RAND() * 10), 
            'Brian', 'Kevin', 'Grace', 'Faith', 'Dennis', 'Mary', 'Peter', 'Joy', 'James', 'Hope');
        SET v_last_name = ELT(FLOOR(1 + RAND() * 10),
            'Ochieng', 'Kamau', 'Mwangi', 'Otieno', 'Njoroge', 'Kimani', 'Wambui', 'Kariuki', 'Akinyi', 'Kipchoge');
        
        
        SET v_dob = DATE_SUB(CURDATE(), INTERVAL (3 + FLOOR(RAND() * 12)) YEAR);
        
        
        INSERT IGNORE INTO students (
            admission_no, first_name, last_name, date_of_birth, gender, 
            stream_id, student_type_id, admission_date, status, created_at, updated_at
        ) VALUES (
            v_admission_no, v_first_name, v_last_name, v_dob, v_gender,
            p_stream_id, 1, '2026-01-06', 'active', NOW(), NOW()
        );
        
        SET i = i + 1;
    END WHILE;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_add_custom_stream` (IN `p_class_id` INT UNSIGNED, IN `p_stream_name` VARCHAR(50), IN `p_capacity` INT, IN `p_teacher_id` INT UNSIGNED)   BEGIN
