CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_assign_role` (IN `p_user_id` INT UNSIGNED, IN `p_role_name` VARCHAR(50), IN `p_assigned_by` INT UNSIGNED, IN `p_reason` VARCHAR(255), OUT `p_success` TINYINT)  MODIFIES SQL DATA BEGIN
    DECLARE role_id INT UNSIGNED;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        SET p_success = 0;
    END;
    
    
    SELECT id INTO role_id FROM roles WHERE name = p_role_name LIMIT 1;
    
    IF role_id IS NULL THEN
        SET p_success = 0;
    ELSE
        INSERT IGNORE INTO user_roles (user_id, role_id)
        VALUES (p_user_id, role_id);
        
        
        IF EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.TABLES 
            WHERE TABLE_SCHEMA = 'KingsWayAcademy' AND TABLE_NAME = 'permission_audit_log') THEN
            INSERT INTO permission_audit_log (action, user_id, role_id, changed_by, reason)
            VALUES ('assign_role', p_user_id, role_id, p_assigned_by, p_reason);
        END IF;
        
        SET p_success = 1;
    END IF;
END$$

