CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_assign_student_transport` (IN `p_student_id` INT, IN `p_route_id` INT, IN `p_stop_id` INT, IN `p_month` INT, IN `p_year` INT)   BEGIN
    INSERT INTO transport_payments (
        student_id, amount, payment_method, status, paid_at
    )
    SELECT p_student_id, 0.00, 'pending', 'pending', NOW()
    WHERE NOT EXISTS (
        SELECT 1 FROM transport_payments
        WHERE student_id = p_student_id
          AND MONTH(paid_at) = p_month AND YEAR(paid_at) = p_year
    );

    
    
    SELECT
        p_student_id AS student_id,
        p_route_id AS route_id,
        p_stop_id AS stop_id,
        p_month AS month,
        p_year AS year,
        'assigned' AS status;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_auto_generate_onboarding_tasks` (IN `p_staff_id` INT)   BEGIN
    
    INSERT IGNORE INTO staff_onboarding (
        staff_id, task_name, task_category, status, due_date, created_at
    )
    SELECT
        p_staff_id,
        task_template,
        category,
        'pending',
        DATE_ADD(CURDATE(), INTERVAL 7 DAY),
        NOW()
    FROM (
        SELECT 'Submit ID documents' AS task_template, 'Documentation' AS category
        UNION ALL SELECT 'Complete contract signing', 'HR'
        UNION ALL SELECT 'Bank account setup', 'Payroll'
        UNION ALL SELECT 'System access registration', 'IT'
        UNION ALL SELECT 'Health & safety briefing', 'Compliance'
        UNION ALL SELECT 'Departmental orientation', 'Orientation'
        UNION ALL SELECT 'Teaching timetable assignment', 'Academic'
    ) AS defaults;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_auto_rollover_fee_structures` (IN `p_from_year` INT, IN `p_to_year` INT, IN `p_apply_increase` TINYINT, OUT `p_copied` INT, OUT `p_log_id` INT)   BEGIN
    DECLARE v_copied INT DEFAULT 0;

    INSERT INTO fee_structures_detailed (
        level_id, academic_year, term_id, student_type_id, fee_type_id,
        amount, status, is_auto_rollover, copied_from_id,
        rollover_notes, created_by, created_at
    )
    SELECT
        level_id, p_to_year, term_id, student_type_id, fee_type_id,
        CASE WHEN p_apply_increase = 1 THEN ROUND(amount * 1.1, 2) ELSE amount END,
        'draft', 1, id,
        CONCAT('Auto-rolled from ', p_from_year), created_by, NOW()
    FROM fee_structures_detailed
    WHERE academic_year = p_from_year AND status = 'active';

    SET v_copied = ROW_COUNT();
    SET p_copied = v_copied;

    INSERT INTO fee_structure_rollover_log (
        from_year, to_year, records_copied, applied_increase, created_at
    ) VALUES (
        p_from_year, p_to_year, v_copied, p_apply_increase, NOW()
    );

    SET p_log_id = LAST_INSERT_ID();
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_broadcast_notification` (IN `p_title` VARCHAR(255), IN `p_message` TEXT, IN `p_notification_type` VARCHAR(50), IN `p_target_user_ids` VARCHAR(1000), IN `p_priority` VARCHAR(20), IN `p_created_by` INT UNSIGNED)   BEGIN
DECLARE v_error_msg VARCHAR(255);
DECLARE v_notification_id INT UNSIGNED;
DECLARE v_user_id INT UNSIGNED;
DECLARE v_temp_id VARCHAR(20);
DECLARE v_remaining VARCHAR(1000);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = v_error_msg;
END;

IF p_target_user_ids IS NULL
OR p_target_user_ids = '' THEN
SET p_target_user_ids = '0';

END IF;

SET v_remaining = CONCAT(p_target_user_ids, ',');
WHILE LOCATE(',', v_remaining) > 0 DO
SET v_temp_id = TRIM(SUBSTRING_INDEX(v_remaining, ',', 1));
SET v_user_id = CAST(v_temp_id AS UNSIGNED);
INSERT INTO notifications (
    user_id,
    title,
    message,
    notification_type,
    priority,
    status,
    created_by,
    created_at
  )
VALUES (
    NULLIF(v_user_id, 0),
    p_title,
    p_message,
    p_notification_type,
    p_priority,
    'unread',
    p_created_by,
    NOW()
  );
SET v_remaining = SUBSTRING(v_remaining, LOCATE(',', v_remaining) + 1);
END WHILE;
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'notification_broadcast',
    JSON_OBJECT(
      'title',
      p_title,
      'type',
      p_notification_type,
      'created_by',
      p_created_by
    ),
    NOW()
  );
END$$

