CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_deny_permission` (IN `p_user_id` INT UNSIGNED, IN `p_permission_code` VARCHAR(255), IN `p_reason` VARCHAR(255), IN `p_changed_by` INT UNSIGNED, OUT `p_success` TINYINT)  MODIFIES SQL DATA BEGIN
    DECLARE perm_id INT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        SET p_success = 0;
    END;
    
    
    SELECT id INTO perm_id FROM permissions WHERE code = p_permission_code LIMIT 1;
    
    IF perm_id IS NULL THEN
        SET p_success = 0;
    ELSE
        INSERT INTO user_permissions (user_id, permission_id, permission_type, reason, granted_by)
        VALUES (p_user_id, perm_id, 'deny', p_reason, p_changed_by)
        ON DUPLICATE KEY UPDATE 
            permission_type = 'deny',
            reason = p_reason,
            updated_at = NOW();
        
        
        IF EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.TABLES 
            WHERE TABLE_SCHEMA = 'KingsWayAcademy' AND TABLE_NAME = 'permission_audit_log') THEN
            INSERT INTO permission_audit_log (action, user_id, permission_id, changed_by, reason)
            VALUES ('deny_permission', p_user_id, perm_id, p_changed_by, p_reason);
        END IF;
        
        SET p_success = 1;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_detect_schedule_conflicts` (IN `p_class_id` INT, IN `p_term_id` INT)   BEGIN
    
    SELECT
        cs1.id AS schedule_1_id,
        cs2.id AS schedule_2_id,
        cs1.day_of_week,
        cs1.start_time,
        cs1.end_time,
        'time_overlap' AS conflict_type
    FROM class_schedules cs1
    JOIN class_schedules cs2 ON cs1.id < cs2.id
        AND cs1.class_id = cs2.class_id
        AND cs1.day_of_week = cs2.day_of_week
        AND cs1.start_time < cs2.end_time
        AND cs1.end_time > cs2.start_time
    WHERE cs1.class_id = p_class_id
      AND cs1.term_id = p_term_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_end_user_session` (IN `p_session_token` VARCHAR(255))   BEGIN
DECLARE v_user_id INT UNSIGNED;
SELECT user_id INTO v_user_id
FROM user_sessions
WHERE session_token = p_session_token;
UPDATE user_sessions
SET session_status = 'logged_out',
  logout_time = NOW()
WHERE session_token = p_session_token;
INSERT INTO system_events (event_type, event_data)
VALUES (
    'user_session_ended',
    JSON_OBJECT('user_id', v_user_id)
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_enroll_student_in_class` (IN `p_student_id` INT UNSIGNED, IN `p_academic_year_id` INT UNSIGNED, IN `p_class_id` INT UNSIGNED, IN `p_stream_id` INT UNSIGNED, IN `p_enrollment_date` DATE, OUT `p_enrollment_id` INT UNSIGNED)   BEGIN
    DECLARE v_academic_year_id INT UNSIGNED;
    DECLARE v_existing_enrollment_id INT UNSIGNED;
    DECLARE v_enrollment_date DATE;
    
    
    IF p_academic_year_id IS NULL THEN
        SELECT id INTO v_academic_year_id 
        FROM academic_years 
        WHERE is_current = 1 
        LIMIT 1;
    ELSE
        SET v_academic_year_id = p_academic_year_id;
    END IF;
    
    
    SET v_enrollment_date = COALESCE(p_enrollment_date, CURDATE());
    
    
    SELECT id INTO v_existing_enrollment_id 
    FROM class_enrollments 
    WHERE student_id = p_student_id 
      AND academic_year_id = v_academic_year_id
      AND enrollment_status IN ('enrolled', 'active')
    LIMIT 1;
    
    IF v_existing_enrollment_id IS NOT NULL THEN
        
        UPDATE class_enrollments 
        SET class_id = p_class_id,
            stream_id = p_stream_id,
            updated_at = NOW()
        WHERE id = v_existing_enrollment_id;
        
        SET p_enrollment_id = v_existing_enrollment_id;
    ELSE
        
        INSERT INTO class_enrollments (
            student_id, 
            academic_year_id, 
            class_id, 
            stream_id,
            enrollment_status,
            enrollment_date,
            promotion_status,
            created_at
        ) VALUES (
            p_student_id,
            v_academic_year_id,
            p_class_id,
            p_stream_id,
            'enrolled',
            v_enrollment_date,
            'none',
            NOW()
        );
        
        SET p_enrollment_id = LAST_INSERT_ID();
    END IF;
    
    
    UPDATE students 
    SET stream_id = p_stream_id 
    WHERE id = p_student_id;
    
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_ensure_class_streams` (IN `p_class_id` INT UNSIGNED)   BEGIN
DECLARE v_stream_count INT;
DECLARE v_active_custom_streams INT;
DECLARE v_class_name VARCHAR(50);
DECLARE v_class_capacity INT;
DECLARE v_teacher_id INT UNSIGNED;
DECLARE v_default_stream_id INT UNSIGNED;
DECLARE v_error_msg VARCHAR(255);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = v_error_msg;
END;

SELECT name,
  capacity,
  teacher_id INTO v_class_name,
  v_class_capacity,
  v_teacher_id
FROM classes
WHERE id = p_class_id;
IF v_class_name IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Class not found';
END IF;

SELECT COUNT(*) INTO v_stream_count
FROM class_streams
WHERE class_id = p_class_id;

IF v_stream_count = 0 THEN
INSERT INTO class_streams (
    class_id,
    stream_name,
    capacity,
    teacher_id,
    status
  )
VALUES (
    p_class_id,
    v_class_name,
    v_class_capacity,
    v_teacher_id,
    'active'
  );
END IF;

IF v_stream_count > 0 THEN 
SELECT COUNT(*) INTO v_active_custom_streams
FROM class_streams cs
  INNER JOIN classes c ON cs.class_id = c.id
WHERE cs.class_id = p_class_id
  AND cs.status = 'active'
  AND cs.stream_name != c.name;


IF v_active_custom_streams > 0 THEN
UPDATE class_streams cs
  INNER JOIN classes c ON cs.class_id = c.id
SET cs.status = 'inactive'
WHERE cs.class_id = p_class_id
  AND cs.stream_name = c.name
  AND cs.status = 'active';
END IF;

IF v_active_custom_streams = 0 THEN
UPDATE class_streams cs
  INNER JOIN classes c ON cs.class_id = c.id
SET cs.status = 'active'
WHERE cs.class_id = p_class_id
  AND cs.stream_name = c.name
  AND cs.status = 'inactive';
END IF;
END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_api_token` (IN `p_user_id` INT UNSIGNED, IN `p_token_name` VARCHAR(100), IN `p_scope` JSON, IN `p_days_valid` INT, OUT `p_token_id` INT UNSIGNED)   BEGIN
DECLARE v_token_hash VARCHAR(255);
DECLARE v_expiry_date DATETIME;
SET v_token_hash = SHA2(CONCAT(p_user_id, UUID(), UNIX_TIMESTAMP()), 256);
SET v_expiry_date = CASE
    WHEN p_days_valid > 0 THEN DATE_ADD(NOW(), INTERVAL p_days_valid DAY)
    ELSE NULL
  END;
INSERT INTO api_tokens (
    user_id,
    token_hash,
    token_name,
    scope,
    created_date,
    expiry_date,
    is_active
  )
VALUES (
    p_user_id,
    v_token_hash,
    p_token_name,
    p_scope,
    NOW(),
    v_expiry_date,
    1
  );
SET p_token_id = LAST_INSERT_ID();
INSERT INTO system_events (event_type, event_data)
VALUES (
    'api_token_created',
    JSON_OBJECT('user_id', p_user_id, 'token_id', p_token_id)
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_comment` (IN `p_grade` VARCHAR(4), OUT `p_comment` VARCHAR(255))   BEGIN
SET p_comment = CASE
    p_grade
    WHEN 'EE1' THEN 'Outstanding performance. Exceeds expectations.'
    WHEN 'EE2' THEN 'Excellent work. Exceeds expectations.'
    WHEN 'ME1' THEN 'Good job. Meets expectations.'
    WHEN 'ME2' THEN 'Satisfactory. Meets expectations.'
    WHEN 'AE1' THEN 'Fair effort. Approaching expectations.'
    WHEN 'AE2' THEN 'Needs improvement. Approaching expectations.'
    WHEN 'BE1' THEN 'Below expectations. Significant improvement needed.'
    WHEN 'BE2' THEN 'Far below expectations. Urgent intervention required.'
    ELSE 'No comment.'
  END;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_p9_form` (IN `p_staff_id` INT, IN `p_year` INT)   BEGIN
    SELECT
        s.id AS staff_id,
        CONCAT(u.first_name, ' ', u.last_name) AS staff_name,
        s.kra_pin,
        SUM(ps.basic_salary) AS total_basic,
        SUM(COALESCE(ps.allowances_total, 0)) AS total_allowances,
        SUM(COALESCE(ps.gross_pay, 0)) AS total_gross,
        SUM(COALESCE(ps.paye_tax, 0)) AS total_paye,
        SUM(COALESCE(ps.nssf_employee, 0)) AS total_nssf,
        SUM(COALESCE(ps.nhif_amount, 0)) AS total_nhif,
        p_year AS tax_year
    FROM staff s
    JOIN users u ON u.id = s.user_id
    JOIN payslips ps ON ps.staff_id = s.id
    WHERE s.id = p_staff_id
      AND YEAR(ps.pay_period_end) = p_year
      AND ps.status = 'paid'
    GROUP BY s.id, u.first_name, u.last_name, s.kra_pin;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_performance_rating` (IN `p_staff_id` INT UNSIGNED, IN `p_rating_period` VARCHAR(20), IN `p_supervisor_id` INT UNSIGNED, IN `p_supervisor_rating` VARCHAR(20), IN `p_comments` TEXT)   BEGIN
DECLARE v_achievement_score DECIMAL(5, 2);
DECLARE v_overall_rating VARCHAR(20);
DECLARE v_academic_year INT;
SET v_academic_year = YEAR(CURDATE());
CALL sp_calculate_kpi_achievement_score(p_staff_id, v_academic_year, v_achievement_score);
SET v_overall_rating = CASE
    WHEN v_achievement_score >= 90 THEN 'Excellent'
    WHEN v_achievement_score >= 75 THEN 'Good'
    WHEN v_achievement_score >= 60 THEN 'Average'
    WHEN v_achievement_score >= 45 THEN 'Below Average'
    ELSE 'Poor'
  END;
INSERT INTO performance_ratings (
    staff_id,
    rating_period,
    overall_rating,
    kpi_achievement_score,
    supervisor_rating,
    supervisor_id,
    rated_date,
    comments
  )
VALUES (
    p_staff_id,
    p_rating_period,
    v_overall_rating,
    v_achievement_score,
    p_supervisor_rating,
    p_supervisor_id,
    CURDATE(),
    p_comments
  );
INSERT INTO system_events (event_type, event_data)
VALUES (
    'performance_rating_created',
    JSON_OBJECT(
      'staff_id',
      p_staff_id,
      'rating',
      v_overall_rating,
      'score',
      v_achievement_score
    )
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_school_year_report` (IN `p_student_id` INT UNSIGNED, IN `p_academic_year` YEAR)   BEGIN
DECLARE v_attendance_percentage DECIMAL(5, 2);
DECLARE v_total_classes INT;
DECLARE v_classes_present INT;

SELECT ROUND(
    SUM(
      CASE
        WHEN status = 'present' THEN 1
        ELSE 0
      END
    ) * 100 / COUNT(*),
    2
  ),
  COUNT(*),
  SUM(
    CASE
      WHEN status = 'present' THEN 1
      ELSE 0
    END
  ) INTO v_attendance_percentage,
  v_total_classes,
  v_classes_present
FROM student_attendance
WHERE student_id = p_student_id
  AND YEAR(attendance_date) = p_academic_year;

SELECT 'School Year Report' as report_type,
  s.admission_no,
  CONCAT(s.first_name, ' ', s.last_name) as student_name,
  s.date_of_birth,
  s.gender,
  cs.class_name as current_class,
  p_academic_year as academic_year,
  v_attendance_percentage as attendance_percentage,
  v_total_classes as total_school_days,
  v_classes_present as days_present,
  (
    SELECT COUNT(*)
    FROM learner_competencies
    WHERE student_id = p_student_id
      AND academic_year = p_academic_year
  ) as competencies_assessed,
  (
    SELECT COUNT(*)
    FROM learner_values_acquisition
    WHERE student_id = p_student_id
      AND academic_year = p_academic_year
  ) as values_demonstrated,
  (
    SELECT COALESCE(SUM(hours_contributed), 0)
    FROM learner_csl_participation
    WHERE student_id = p_student_id
      AND academic_year = p_academic_year
  ) as csl_hours,
  (
    SELECT conduct_rating
    FROM conduct_tracking
    WHERE student_id = p_student_id
      AND academic_year = p_academic_year
    LIMIT 1
  ) as conduct_rating
FROM students s
  JOIN class_streams cs ON s.stream_id = cs.id
WHERE s.id = p_student_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_student_fee_obligations` (IN `p_student_id` INT UNSIGNED, IN `p_academic_year_id` INT UNSIGNED, IN `p_term_id` INT UNSIGNED, OUT `p_obligations_created` INT)   BEGIN
    DECLARE v_academic_year_id INT UNSIGNED;
    DECLARE v_academic_year YEAR;
    DECLARE v_student_type_id INT UNSIGNED;
    DECLARE v_level_id INT UNSIGNED;
    DECLARE v_is_sponsored TINYINT;
    DECLARE v_sponsor_waiver_percentage DECIMAL(5,2);
    
    SET p_obligations_created = 0;
    
    
    IF p_academic_year_id IS NULL THEN
        SELECT id, YEAR(start_date) INTO v_academic_year_id, v_academic_year
        FROM academic_years 
        WHERE is_current = 1 
        LIMIT 1;
    ELSE
        SELECT id, YEAR(start_date) INTO v_academic_year_id, v_academic_year
        FROM academic_years 
        WHERE id = p_academic_year_id;
    END IF;
    
    
    SELECT 
        s.student_type_id,
        COALESCE(cs.level_id, c.level_id) as level_id,
        s.is_sponsored,
        s.sponsor_waiver_percentage
    INTO 
        v_student_type_id,
        v_level_id,
        v_is_sponsored,
        v_sponsor_waiver_percentage
    FROM students s
    LEFT JOIN class_streams cs ON s.stream_id = cs.id
    LEFT JOIN classes c ON cs.class_id = c.id
    WHERE s.id = p_student_id;
    
    
    INSERT INTO student_fee_obligations (
        student_id,
        fee_structure_detail_id,
        academic_year_id,
        term_id,
        amount_due,
        amount_paid,
        amount_waived,
        balance,
        waiver_percentage,
        waiver_reason,
        payment_status,
        due_date,
        created_at
    )
    SELECT 
        p_student_id,
        fsd.id,
        v_academic_year_id,
        fsd.term_id,
        fsd.amount,
        0, 
        CASE 
            WHEN v_is_sponsored = 1 AND v_sponsor_waiver_percentage > 0 
            THEN ROUND(fsd.amount * (v_sponsor_waiver_percentage / 100), 2)
            ELSE 0
        END, 
        CASE 
            WHEN v_is_sponsored = 1 AND v_sponsor_waiver_percentage > 0 
            THEN fsd.amount - ROUND(fsd.amount * (v_sponsor_waiver_percentage / 100), 2)
            ELSE fsd.amount
        END, 
        v_sponsor_waiver_percentage,
        CASE 
            WHEN v_is_sponsored = 1 THEN 'Sponsorship waiver'
            ELSE NULL
        END,
        'unpaid',
        COALESCE(fsd.due_date, DATE_ADD(CURDATE(), INTERVAL 30 DAY)),
        NOW()
    FROM fee_structures_detailed fsd
    WHERE fsd.level_id = v_level_id
      AND fsd.academic_year = v_academic_year
      AND fsd.student_type_id = v_student_type_id
      AND fsd.status = 'approved'
      AND (p_term_id IS NULL OR fsd.term_id = p_term_id)
      AND NOT EXISTS (
          SELECT 1 FROM student_fee_obligations sfo 
          WHERE sfo.student_id = p_student_id 
            AND sfo.fee_structure_detail_id = fsd.id
            AND sfo.academic_year_id = v_academic_year_id
      );
    
    SET p_obligations_created = ROW_COUNT();
    
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_student_report` (IN `p_student_id` INT UNSIGNED, IN `p_term_id` INT UNSIGNED)   BEGIN
  
  SELECT
    s.admission_number,
    s.first_name,
    s.last_name,
    gl.name AS grade_level,
    c.name AS class_name,
    at.name AS academic_term,
    
    COUNT(DISTINCT ca.id) AS total_assessments,
    AVG(ca.overall_score) AS average_score,
    
    COUNT(DISTINCT sa.id) AS total_school_days,
    COUNT(DISTINCT CASE WHEN sa.status = 'present' THEN sa.id END) AS days_present,
    
    tr.name AS transport_route,
    rs.name AS pickup_point,
    
    calculate_term_fees(p_student_id, p_term_id) AS term_fees,
    COALESCE(SUM(fp.amount), 0) AS fees_paid,
    calculate_term_fees(p_student_id, p_term_id) - COALESCE(SUM(fp.amount), 0) AS balance
  FROM students s
  JOIN grade_levels gl ON s.grade_level_id = gl.id
  JOIN classes c ON s.class_id = c.id
  JOIN academic_terms at ON at.id = p_term_id
  LEFT JOIN cbc_assessments ca ON s.id = ca.student_id AND ca.term_id = p_term_id
  LEFT JOIN student_attendance sa ON s.id = sa.student_id AND sa.term_id = p_term_id
  LEFT JOIN student_transport st ON s.id = st.student_id AND st.academic_term_id = p_term_id
  LEFT JOIN transport_routes tr ON st.route_id = tr.id
  LEFT JOIN route_stops rs ON st.stop_id = rs.id
  LEFT JOIN student_fee_balances sfb ON s.id = sfb.student_id AND sfb.academic_term_id = p_term_id
  LEFT JOIN fee_payments fp ON sfb.id = fp.fee_balance_id
  WHERE s.id = p_student_id
  GROUP BY s.id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_assessment_trends` (IN `p_student_id` INT UNSIGNED, IN `p_subject_id` INT UNSIGNED)   BEGIN
SELECT at.year,
  at.term_number,
  at.name AS term_name,
  cu.name AS subject_name,
  tss.overall_percentage,
  tss.overall_grade,
  tss.formative_percentage,
  tss.summative_percentage,
  tss.assessment_count
FROM term_subject_scores tss
  JOIN academic_terms at ON tss.term_id = at.id
  JOIN curriculum_units cu ON tss.subject_id = cu.id
WHERE tss.student_id = p_student_id
  AND (
    p_subject_id = 0
    OR tss.subject_id = p_subject_id
  )
ORDER BY at.year DESC,
  at.term_number DESC;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_class_fee_schedule` (IN `p_class_id` INT, IN `p_year` INT)   BEGIN
    SELECT
        ft.name AS fee_type,
        fsd.amount,
        fsd.due_date,
        st.name AS student_type
    FROM fee_structures_detailed fsd
    JOIN fee_types ft ON ft.id = fsd.fee_type_id
    JOIN student_types st ON st.id = fsd.student_type_id
    JOIN class_year_assignments cya ON cya.class_id = p_class_id
        AND cya.level_id = fsd.level_id
    WHERE fsd.academic_year = p_year
      AND fsd.status = 'active'
    ORDER BY ft.name, st.name;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_competency_report` (IN `p_student_id` INT UNSIGNED, IN `p_academic_year` YEAR)   BEGIN
SELECT cc.code,
  cc.name,
  lc.term_id,
  plc.level,
  plc.name as performance_level,
  lc.evidence,
  lc.teacher_notes,
  lc.assessed_date
FROM learner_competencies lc
  JOIN core_competencies cc ON lc.competency_id = cc.id
  LEFT JOIN performance_levels_cbc plc ON lc.performance_level_id = plc.id
WHERE lc.student_id = p_student_id
  AND lc.academic_year = p_academic_year
ORDER BY cc.sort_order,
  lc.term_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_dormitory_students` (IN `p_dormitory_id` INT, IN `p_date` DATE, IN `p_session_id` INT)   BEGIN
    SELECT 
        s.id,
        s.admission_no,
        CONCAT(s.first_name, ' ', s.last_name) as student_name,
        c.name as class_name,
        da.bed_number,
        ba.status as current_status,
        ba.check_time,
        ba.notes,
        sp.id as permission_id,
        spt.name as permission_type,
        sp.end_date as permission_until
    FROM dormitory_assignments da
    JOIN students s ON da.student_id = s.id
    JOIN class_streams cs ON s.stream_id = cs.id
    JOIN classes c ON cs.class_id = c.id
    LEFT JOIN boarding_attendance ba ON s.id = ba.student_id 
        AND ba.date = p_date 
        AND ba.session_id = p_session_id
        AND ba.dormitory_id = p_dormitory_id
    LEFT JOIN student_permissions sp ON s.id = sp.student_id
        AND p_date BETWEEN sp.start_date AND sp.end_date
        AND sp.status = 'approved'
    LEFT JOIN student_permission_types spt ON sp.permission_type_id = spt.id
    WHERE da.dormitory_id = p_dormitory_id
        AND da.status = 'active'
        AND s.status = 'active'
    ORDER BY s.last_name, s.first_name;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_family_group_details` (IN `p_parent_id` INT)   BEGIN
    SELECT
        u.id AS parent_id,
        u.first_name, u.last_name, u.email,
        sp.relationship,
        sp.is_primary_contact, sp.is_emergency_contact,
        sp.financial_responsibility
    FROM users u
    LEFT JOIN student_parents sp ON sp.parent_id = u.id
    WHERE u.id = p_parent_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_fee_breakdown_for_review` (IN `p_year` INT, IN `p_term` INT)   BEGIN
    SELECT
        l.name AS level_name,
        ft.name AS fee_type,
        st.name AS student_type,
        fsd.amount,
        fsd.status,
        fsd.due_date
    FROM fee_structures_detailed fsd
    JOIN fee_types ft ON ft.id = fsd.fee_type_id
    JOIN student_types st ON st.id = fsd.student_type_id
    JOIN school_levels l ON l.id = fsd.level_id
    WHERE fsd.academic_year = p_year
      AND fsd.term_id = p_term
    ORDER BY l.name, ft.name, st.name;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_fee_collection_rate` (IN `p_year` INT, IN `p_term` INT)   BEGIN
    SELECT
        SUM(CASE WHEN pt.status = 'confirmed' THEN pt.amount_paid ELSE 0 END) AS total_collected,
        COUNT(DISTINCT sfo.student_id) AS students_with_fees,
        COUNT(DISTINCT CASE WHEN pt.status = 'confirmed' THEN pt.student_id END) AS students_paid,
        ROUND(
            100.0 * SUM(CASE WHEN pt.status = 'confirmed' THEN pt.amount_paid ELSE 0 END)
            / NULLIF(SUM(sfo.amount_due), 0),
            2
        ) AS collection_rate_percent
    FROM student_fee_obligations sfo
    LEFT JOIN payment_transactions pt ON pt.student_id = sfo.student_id
        AND pt.term_id = p_term
        AND pt.academic_year = p_year
    WHERE sfo.term_id = p_term;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_outstanding_fees_report` (IN `p_year` INT, IN `p_term` INT)   BEGIN
    SELECT
        s.id AS student_id,
        s.admission_no,
        CONCAT(s.first_name, ' ', s.last_name) AS student_name,
        sfb.balance AS outstanding_amount,
        c.name AS class_name
    FROM student_fee_balances sfb
    JOIN students s ON s.id = sfb.student_id
    LEFT JOIN class_enrollments ce ON ce.student_id = s.id
        AND ce.academic_year_id = (SELECT id FROM academic_years WHERE year_label = p_year LIMIT 1)
    LEFT JOIN classes c ON c.id = ce.class_id
    WHERE sfb.balance > 0
    ORDER BY sfb.balance DESC;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_parent_children` (IN `p_parent_id` INT)   BEGIN
    SELECT
        s.id AS student_id,
        s.admission_no,
        s.first_name, s.last_name,
        s.gender, s.status,
        sp.relationship,
        sp.is_primary_contact,
        sp.financial_responsibility
    FROM students s
    JOIN student_parents sp ON sp.student_id = s.id
    WHERE sp.parent_id = p_parent_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_payments_by_admission` (IN `p_admission_number` VARCHAR(50), IN `p_limit` INT)   BEGIN
    SELECT 
        payment_source,
        source_id,
        reference_code,
        student_id,
        admission_number,
        student_name,
        amount,
        transaction_date,
        contact,
        status,
        created_at
    FROM vw_payment_tracking
    WHERE admission_number = p_admission_number
    ORDER BY transaction_date DESC
    LIMIT p_limit;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_staff_kpi_summary` (IN `p_staff_id` INT, IN `p_period` VARCHAR(50))   BEGIN
    SELECT
        kd.name AS kpi_name,
        kd.category,
        kt.target_value,
        COALESCE(ka.achieved_value, 0) AS achieved_value,
        ROUND(100.0 * COALESCE(ka.achieved_value, 0) / NULLIF(kt.target_value, 0), 1) AS achievement_percent
    FROM kpi_definitions kd
    LEFT JOIN kpi_targets kt ON kt.kpi_id = kd.id AND kt.staff_id = p_staff_id
    LEFT JOIN kpi_achievements ka ON ka.kpi_id = kd.id AND ka.staff_id = p_staff_id
    WHERE kd.is_active = 1
    ORDER BY kd.category, kd.name;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_user_permissions` (IN `p_user_id` INT UNSIGNED)  READS SQL DATA BEGIN
    
    SELECT DISTINCT 
        p.id,
        p.code as permission_code,
        p.entity,
        p.action,
        p.description,
        'role' as source,
        r.name as role_name
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    JOIN role_permissions rp ON r.id = rp.role_id
    JOIN permissions p ON rp.permission_id = p.id
    WHERE ur.user_id = p_user_id
    
    UNION DISTINCT
    
    SELECT 
        p.id,
        p.code as permission_code,
        p.entity,
        p.action,
        p.description,
        up.permission_type as source,
        NULL as role_name
    FROM user_permissions up
    JOIN permissions p ON up.permission_id = p.id
    WHERE up.user_id = p_user_id
        AND up.permission_type IN ('grant', 'override')
        AND (up.expires_at IS NULL OR up.expires_at > NOW())
    
    ORDER BY permission_code;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_values_summary` (IN `p_student_id` INT UNSIGNED, IN `p_academic_year` YEAR)   BEGIN
SELECT cv.code,
  cv.name,
  COUNT(*) as demonstration_count,
  GROUP_CONCAT(
    CONCAT(
      '[',
      DATE_FORMAT(lva.incident_date, '%Y-%m-%d'),
      '] ',
      lva.evidence
    ) SEPARATOR '; '
  ) as evidences,
  MAX(lva.incident_date) as last_demonstrated
FROM learner_values_acquisition lva
  JOIN core_values cv ON lva.value_id = cv.id
WHERE lva.student_id = p_student_id
  AND lva.academic_year = p_academic_year
GROUP BY cv.id,
  cv.code,
  cv.name
ORDER BY cv.sort_order;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_grant_permission` (IN `p_user_id` INT UNSIGNED, IN `p_permission_code` VARCHAR(255), IN `p_reason` VARCHAR(255), IN `p_granted_by` INT UNSIGNED, IN `p_expires_at` TIMESTAMP, OUT `p_success` TINYINT)  MODIFIES SQL DATA BEGIN
    DECLARE perm_id INT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        SET p_success = 0;
    END;
    
    
    SELECT id INTO perm_id FROM permissions WHERE code = p_permission_code LIMIT 1;
    
    IF perm_id IS NULL THEN
        SET p_success = 0;
    ELSE
        INSERT INTO user_permissions (user_id, permission_id, permission_type, reason, granted_by, expires_at)
        VALUES (p_user_id, perm_id, 'grant', p_reason, p_granted_by, p_expires_at)
        ON DUPLICATE KEY UPDATE 
            permission_type = 'grant',
            reason = p_reason,
            granted_by = p_granted_by,
            expires_at = p_expires_at,
            updated_at = NOW();
        
        
        IF EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.TABLES 
            WHERE TABLE_SCHEMA = 'KingsWayAcademy' AND TABLE_NAME = 'permission_audit_log') THEN
            INSERT INTO permission_audit_log (action, user_id, permission_id, changed_by, reason)
            VALUES ('grant_permission', p_user_id, perm_id, p_granted_by, p_reason);
        END IF;
        
        SET p_success = 1;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_implement_discipline_action` (IN `p_case_id` INT UNSIGNED, IN `p_action_type` ENUM('warning','detention','suspension','expulsion','counseling'), IN `p_action_details` JSON, IN `p_implemented_by` INT UNSIGNED)   BEGIN
    DECLARE v_student_id INT UNSIGNED;
    
    START TRANSACTION;
    
    
    SELECT student_id INTO v_student_id
    FROM student_discipline
    WHERE id = p_case_id;
    
    
    CASE p_action_type
        WHEN 'suspension' THEN
            
            UPDATE students
            SET status = 'suspended',
                suspension_start = JSON_UNQUOTE(JSON_EXTRACT(p_action_details, '$.start_date')),
                suspension_end = JSON_UNQUOTE(JSON_EXTRACT(p_action_details, '$.end_date'))
            WHERE id = v_student_id;
            
        WHEN 'expulsion' THEN
            
            UPDATE students
            SET status = 'expelled',
                exit_date = CURDATE(),
                exit_reason = 'Disciplinary expulsion'
            WHERE id = v_student_id;
            
        WHEN 'counseling' THEN
            
            INSERT INTO counseling_sessions (
                student_id,
                session_date,
                counselor_id,
                session_type,
                status
            ) VALUES (
                v_student_id,
                JSON_UNQUOTE(JSON_EXTRACT(p_action_details, '$.first_session_date')),
                JSON_UNQUOTE(JSON_EXTRACT(p_action_details, '$.counselor_id')),
                'disciplinary',
                'scheduled'
            );
    END CASE;
    
    
    UPDATE student_discipline
    SET action_taken = p_action_type,
        action_details = p_action_details,
        action_date = NOW(),
        implemented_by = p_implemented_by,
        status = 'action_implemented'
    WHERE id = p_case_id;
    
    
    CALL sp_send_sms_to_parents(
        JSON_ARRAY(v_student_id),
        CONCAT('Discipline action: ', p_action_type, '. Details sent via email.'),
        p_implemented_by
    );
    
    COMMIT;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_initialize_transfer_clearances` (IN `p_transfer_id` INT)   BEGIN
    
    UPDATE students s
    JOIN student_transfers st ON st.student_id = s.id
    SET s.status = 'inactive'
    WHERE st.id = p_transfer_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_issue_allocation` (IN `p_allocation_id` INT UNSIGNED, IN `p_issued_by` INT UNSIGNED)   BEGIN
DECLARE v_error_msg VARCHAR(255);
DECLARE v_item_id INT UNSIGNED;
DECLARE v_allocated_quantity INT;
DECLARE v_status VARCHAR(50);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = v_error_msg;
END;
SELECT status,
  item_id,
  allocated_quantity INTO v_status,
  v_item_id,
  v_allocated_quantity
FROM inventory_allocations
WHERE id = p_allocation_id;
IF v_item_id IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Allocation not found';
END IF;
IF v_status != 'allocated' THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Allocation cannot be issued (status must be allocated)';
END IF;
UPDATE inventory_allocations
SET status = 'issued',
  issued_by = p_issued_by,
  issued_at = NOW(),
  updated_at = NOW()
WHERE id = p_allocation_id;
INSERT INTO inventory_transactions (
    item_id,
    transaction_type,
    quantity,
    transaction_date,
    created_at,
    reference_type,
    reference_id,
    notes
  )
VALUES (
    v_item_id,
    'out',
    v_allocated_quantity,
    CURDATE(),
    NOW(),
    'allocation',
    p_allocation_id,
    'Allocation issued'
  );
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'allocation_issued',
    JSON_OBJECT('allocation_id', p_allocation_id),
    NOW()
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_link_parent_to_student` (IN `p_parent_id` INT, IN `p_student_id` INT, IN `p_relationship` VARCHAR(50), IN `p_is_primary_contact` TINYINT, IN `p_is_emergency_contact` TINYINT, IN `p_financial_responsibility` DECIMAL(5,2), OUT `p_success` TINYINT)   BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET p_success = 0;
    END;

    INSERT INTO student_parents (
        student_id, parent_id, relationship,
        is_primary_contact, is_emergency_contact, financial_responsibility
    ) VALUES (
        p_student_id, p_parent_id, p_relationship,
        p_is_primary_contact, p_is_emergency_contact, p_financial_responsibility
    ) ON DUPLICATE KEY UPDATE
        relationship = p_relationship,
        is_primary_contact = p_is_primary_contact,
        is_emergency_contact = p_is_emergency_contact,
        financial_responsibility = p_financial_responsibility,
        updated_at = NOW();

    SET p_success = 1;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_mark_boarding_attendance` (IN `p_student_id` INT, IN `p_dormitory_id` INT, IN `p_date` DATE, IN `p_session_id` INT, IN `p_status` VARCHAR(20), IN `p_marked_by` INT, IN `p_notes` TEXT, OUT `p_result` VARCHAR(100))   BEGIN
    DECLARE existing_id INT;
    DECLARE permission_id INT;
    DECLARE final_status VARCHAR(20);
    
    
    SET permission_id = fn_student_has_permission(p_student_id, p_date);
    
    
    IF p_status = 'absent' AND permission_id IS NOT NULL THEN
        SET final_status = 'permission';
    ELSE
        SET final_status = p_status;
    END IF;
    
    
    SELECT id INTO existing_id 
    FROM boarding_attendance 
    WHERE student_id = p_student_id 
        AND dormitory_id = p_dormitory_id
        AND date = p_date 
        AND session_id = p_session_id;
    
    IF existing_id IS NOT NULL THEN
        UPDATE boarding_attendance 
        SET status = final_status,
            check_time = CURTIME(),
            permission_id = permission_id,
            notes = p_notes,
            marked_by = p_marked_by
        WHERE id = existing_id;
        SET p_result = 'updated';
    ELSE
        INSERT INTO boarding_attendance 
            (student_id, dormitory_id, date, session_id, status, check_time, permission_id, marked_by, notes)
        VALUES 
            (p_student_id, p_dormitory_id, p_date, p_session_id, final_status, CURTIME(), permission_id, p_marked_by, p_notes);
        SET p_result = 'created';
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_mark_uniform_sale_paid` (IN `p_sale_id` INT, IN `p_payment_date` DATE)   BEGIN
    UPDATE uniform_sales
    SET payment_status = 'paid',
        payment_date = COALESCE(p_payment_date, CURDATE()),
        updated_at = NOW()
    WHERE id = p_sale_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_moderate_marks` (IN `p_assessment_id` INT UNSIGNED, IN `p_moderated_by` INT UNSIGNED)   BEGIN
    DECLARE v_class_avg DECIMAL(5,2);
    DECLARE v_expected_avg DECIMAL(5,2) DEFAULT 65.00; 
    DECLARE v_adjustment_factor DECIMAL(5,4);
    DECLARE v_max_marks DECIMAL(6,2);
    
    START TRANSACTION;
    
    
    SELECT max_marks INTO v_max_marks
    FROM assessments
    WHERE id = p_assessment_id;
    
    
    SELECT AVG(marks_obtained) INTO v_class_avg
    FROM assessment_results
    WHERE assessment_id = p_assessment_id;
    
    
    IF v_class_avg < 50 OR v_class_avg > 80 THEN
        SET v_adjustment_factor = v_expected_avg / v_class_avg;
        
        
        IF v_adjustment_factor > 1.15 THEN
            SET v_adjustment_factor = 1.15; 
        ELSEIF v_adjustment_factor < 0.85 THEN
            SET v_adjustment_factor = 0.85; 
        END IF;
        
        
        UPDATE assessment_results
        SET marks_obtained = LEAST(
                ROUND(marks_obtained * v_adjustment_factor, 2),
                v_max_marks
            ),
            grade = calculate_grade(LEAST(
                ROUND((marks_obtained * v_adjustment_factor / v_max_marks) * 100, 2),
                100.00
            )),
            points = calculate_points(LEAST(
                ROUND((marks_obtained * v_adjustment_factor / v_max_marks) * 100, 2),
                100.00
            ))
        WHERE assessment_id = p_assessment_id;
        
        
        INSERT INTO assessment_history (
            assessment_result_id,
            student_id,
            assessment_id,
            old_marks,
            new_marks,
            change_reason,
            changed_by
        )
        SELECT 
            id,
            student_id,
            assessment_id,
            marks_obtained / v_adjustment_factor,
            marks_obtained,
            CONCAT('Moderation applied: factor ', v_adjustment_factor),
            p_moderated_by
        FROM assessment_results
        WHERE assessment_id = p_assessment_id;
    END IF;
    
    
    UPDATE assessments
    SET status = 'approved',
        approved_by = p_moderated_by,
        approved_at = NOW()
    WHERE id = p_assessment_id;
    
    COMMIT;
    
    
    SELECT 
        v_class_avg AS original_average,
        AVG(marks_obtained) AS moderated_average,
        v_adjustment_factor AS adjustment_factor,
        COUNT(*) AS students_moderated
    FROM assessment_results
    WHERE assessment_id = p_assessment_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_monthly_payroll` (IN `p_month` INT, IN `p_year` INT)   BEGIN
DECLARE done INT DEFAULT FALSE;
DECLARE v_staff_id INT UNSIGNED;
DECLARE v_success_count INT DEFAULT 0;
DECLARE v_error_count INT DEFAULT 0;
DECLARE staff_cursor CURSOR FOR
SELECT id
FROM staff
WHERE status = 'active';
DECLARE CONTINUE HANDLER FOR NOT FOUND
SET done = TRUE;
OPEN staff_cursor;
staff_loop: LOOP FETCH staff_cursor INTO v_staff_id;
IF done THEN LEAVE staff_loop;
END IF;
BEGIN
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN
SET v_error_count = v_error_count + 1;
END;
CALL sp_calculate_payroll_for_staff(v_staff_id, p_month, p_year);
SET v_success_count = v_success_count + 1;
END;
END LOOP;
CLOSE staff_cursor;
INSERT INTO system_events (event_type, event_data)
VALUES (
    'payroll_processing_complete',
    JSON_OBJECT(
      'month',
      p_month,
      'year',
      p_year,
      'success',
      v_success_count,
      'errors',
      v_error_count
    )
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_requisition` (IN `p_requisition_id` INT UNSIGNED, IN `p_action` VARCHAR(50), IN `p_approved_by` INT UNSIGNED, IN `p_rejection_reason` TEXT)   BEGIN
    DECLARE v_error_msg VARCHAR(255);
    DECLARE v_current_status VARCHAR(50);
    DECLARE v_requisition_number VARCHAR(50);

    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_error_msg;
    END;

    
    SELECT status, requisition_number
    INTO v_current_status, v_requisition_number
    FROM inventory_requisitions
    WHERE id = p_requisition_id;

    IF v_requisition_number IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Requisition not found';
    END IF;

    
    CASE p_action
        WHEN 'submit' THEN
            UPDATE inventory_requisitions
            SET status = 'pending_approval',
                updated_at = NOW()
            WHERE id = p_requisition_id
              AND status = 'draft';

        WHEN 'approve' THEN
            IF p_approved_by IS NULL THEN
                SIGNAL SQLSTATE '45000'
                SET MESSAGE_TEXT = 'Approver ID required';
            END IF;

            UPDATE inventory_requisitions
            SET status = 'approved',
                approved_by = p_approved_by,
                approved_at = NOW(),
                updated_at = NOW()
            WHERE id = p_requisition_id
              AND status IN ('draft', 'pending_approval');

        WHEN 'reject' THEN
            IF p_rejection_reason IS NULL THEN
                SIGNAL SQLSTATE '45000'
                SET MESSAGE_TEXT = 'Rejection reason required';
            END IF;

            UPDATE inventory_requisitions
            SET status = 'rejected',
                rejection_reason = p_rejection_reason,
                approved_by = p_approved_by,
                approved_at = NOW(),
                updated_at = NOW()
            WHERE id = p_requisition_id
              AND status IN ('draft', 'pending_approval');

        WHEN 'cancel' THEN
            UPDATE inventory_requisitions
            SET status = 'cancelled',
                updated_at = NOW()
            WHERE id = p_requisition_id
              AND status != 'fulfilled';

        ELSE
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'Invalid action';
    END CASE;

    
    INSERT INTO system_events (event_type, event_data, created_at)
    VALUES (
        CONCAT('requisition_', p_action),
        JSON_OBJECT(
            'requisition_id', p_requisition_id,
            'action', p_action
        ),
        NOW()
    );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_staff_payroll` (IN `p_month` INT, IN `p_year` INT)   BEGIN
DECLARE done INT DEFAULT FALSE;
DECLARE v_staff_id INT UNSIGNED;
DECLARE v_basic_salary DECIMAL(10, 2);
DECLARE v_allowances DECIMAL(10, 2);
DECLARE v_deductions DECIMAL(10, 2);

DECLARE staff_cur CURSOR FOR
SELECT id,
  basic_salary
FROM staff
WHERE status = 'active';
DECLARE CONTINUE HANDLER FOR NOT FOUND
SET done = TRUE;
START TRANSACTION;
OPEN staff_cur;
read_loop: LOOP FETCH staff_cur INTO v_staff_id,
v_basic_salary;
IF done THEN LEAVE read_loop;
END IF;

SELECT COALESCE(SUM(amount), 0) INTO v_allowances
FROM staff_allowances
WHERE staff_id = v_staff_id
  AND MONTH(effective_date) = p_month
  AND YEAR(effective_date) = p_year;

SELECT COALESCE(SUM(amount), 0) INTO v_deductions
FROM staff_deductions
WHERE staff_id = v_staff_id
  AND MONTH(effective_date) = p_month
  AND YEAR(effective_date) = p_year;

INSERT INTO staff_payrolls (
    staff_id,
    payroll_month,
    payroll_year,
    basic_salary,
    allowances,
    deductions,
    net_pay,
    created_at
  )
VALUES (
    v_staff_id,
    p_month,
    p_year,
    v_basic_salary,
    v_allowances,
    v_deductions,
    v_basic_salary + v_allowances - v_deductions,
    NOW()
  );
END LOOP;
CLOSE staff_cur;
COMMIT;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_staff_performance_review` (IN `p_staff_id` INT, OUT `p_score` DECIMAL(5,2), OUT `p_grade` VARCHAR(10))   BEGIN
    SELECT
        COALESCE(AVG(overall_score), 0),
        CASE
            WHEN COALESCE(AVG(overall_score), 0) >= 90 THEN 'A'
            WHEN COALESCE(AVG(overall_score), 0) >= 75 THEN 'B'
            WHEN COALESCE(AVG(overall_score), 0) >= 60 THEN 'C'
            WHEN COALESCE(AVG(overall_score), 0) >= 50 THEN 'D'
            ELSE 'F'
        END
    INTO p_score, p_grade
    FROM staff_performance_reviews
    WHERE staff_id = p_staff_id
      AND status = 'completed'
      AND YEAR(review_date) = YEAR(CURDATE());
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_student_payment` (IN `p_student_id` INT, IN `p_parent_id` INT, IN `p_amount` DECIMAL(10,2), IN `p_payment_method` VARCHAR(50), IN `p_reference_no` VARCHAR(100), IN `p_receipt_no` VARCHAR(50), IN `p_received_by` INT, IN `p_payment_date` DATETIME, IN `p_notes` TEXT)   BEGIN
    DECLARE v_academic_year YEAR;
    DECLARE v_term_id INT;
    DECLARE v_transaction_id INT;

    
    SELECT ay.year_label INTO v_academic_year
    FROM academic_years ay WHERE ay.is_current = 1 LIMIT 1;

    SELECT at2.id INTO v_term_id
    FROM academic_terms at2
    WHERE at2.is_current = 1 LIMIT 1;

    
    INSERT INTO payment_transactions (
        student_id, academic_year, term_id, parent_id,
        amount_paid, payment_date, payment_method,
        reference_no, receipt_no, received_by, status, notes
    ) VALUES (
        p_student_id, v_academic_year, v_term_id, p_parent_id,
        p_amount, COALESCE(p_payment_date, NOW()), p_payment_method,
        p_reference_no, p_receipt_no, p_received_by, 'confirmed', p_notes
    );

    SET v_transaction_id = LAST_INSERT_ID();

    
    UPDATE student_fee_balances
    SET balance = balance - p_amount,
        updated_at = NOW()
    WHERE student_id = p_student_id;

    
    SELECT v_transaction_id AS transaction_id, p_amount AS amount_applied,
           'confirmed' AS status;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_student_sponsorship` (`p_student_id` INT UNSIGNED, `p_is_sponsored` BOOLEAN, `p_sponsor_type` VARCHAR(20), `p_waiver_percentage` DECIMAL(5,2), `p_sponsor_name` VARCHAR(100), OUT `p_result_message` VARCHAR(500))  MODIFIES SQL DATA COMMENT 'Process student sponsorship: update student record and create/update fee waivers' BEGIN
DECLARE p_student_count INT DEFAULT 0;
DECLARE p_existing_waiver_id INT DEFAULT 0;

SELECT COUNT(*) INTO p_student_count
FROM students
WHERE id = p_student_id;
IF p_student_count = 0 THEN
SET p_result_message = CONCAT('ERROR: Student ID ', p_student_id, ' not found');
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = p_result_message;
END IF;

IF p_waiver_percentage < 0
OR p_waiver_percentage > 100 THEN
SET p_result_message = 'ERROR: Waiver percentage must be between 0 and 100';
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = p_result_message;
END IF;

UPDATE students
SET is_sponsored = p_is_sponsored,
  sponsor_type = CASE
    WHEN p_is_sponsored = TRUE THEN p_sponsor_type
    ELSE NULL
  END,
  sponsor_waiver_percentage = CASE
    WHEN p_is_sponsored = TRUE THEN p_waiver_percentage
    ELSE 0
  END,
  sponsor_name = CASE
    WHEN p_is_sponsored = TRUE THEN p_sponsor_name
    ELSE NULL
  END,
  updated_at = NOW()
WHERE id = p_student_id;

IF p_is_sponsored = TRUE THEN 
SELECT fe.id INTO p_existing_waiver_id
FROM fee_discounts_waivers fe
WHERE fe.student_id = p_student_id
  AND fe.waiver_type = 'sponsorship'
  AND YEAR(fe.created_at) = YEAR(NOW())
LIMIT 1;
IF p_existing_waiver_id IS NOT NULL THEN 
UPDATE fee_discounts_waivers
SET waiver_type = 'sponsorship',
  waiver_percentage = p_waiver_percentage,
  description = CONCAT(
    'Sponsorship by ',
    p_sponsor_name,
    ' - ',
    p_sponsor_type
  ),
  is_active = TRUE,
  updated_at = NOW()
WHERE id = p_existing_waiver_id;
SET p_result_message = CONCAT(
    'SUCCESS: Sponsorship updated for student ',
    p_student_id,
    ' with ',
    p_waiver_percentage,
    '% waiver'
  );
ELSE 
INSERT INTO fee_discounts_waivers (
    student_id,
    waiver_type,
    waiver_percentage,
    description,
    created_by,
    is_active
  )
VALUES (
    p_student_id,
    'sponsorship',
    p_waiver_percentage,
    CONCAT(
      'Sponsorship by ',
      p_sponsor_name,
      ' - ',
      p_sponsor_type
    ),
    1,
    TRUE
  );
SET p_result_message = CONCAT(
    'SUCCESS: Sponsorship activated for student ',
    p_student_id,
    ' with ',
    p_waiver_percentage,
    '% waiver'
  );
END IF;

UPDATE student_fee_obligations
SET is_sponsored = TRUE,
  sponsored_waiver_amount = amount_due * (p_waiver_percentage / 100),
  updated_at = NOW()
WHERE student_id = p_student_id
  AND payment_status != 'paid';
ELSE 
UPDATE fee_discounts_waivers
SET is_active = FALSE,
  updated_at = NOW()
WHERE student_id = p_student_id
  AND waiver_type = 'sponsorship';
UPDATE student_fee_obligations
SET is_sponsored = FALSE,
  sponsored_waiver_amount = 0,
  updated_at = NOW()
WHERE student_id = p_student_id;
SET p_result_message = CONCAT(
    'SUCCESS: Sponsorship deactivated for student ',
    p_student_id
  );
END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_promote_bulk_students` (IN `p_batch_id` INT UNSIGNED, IN `p_from_year` YEAR, IN `p_to_year` YEAR, IN `p_student_ids` JSON)   BEGIN
DECLARE v_batch_status VARCHAR(50);
DECLARE v_error_msg VARCHAR(255);
DECLARE v_index INT DEFAULT 0;
DECLARE v_student_count INT;
DECLARE v_student_id INT;
DECLARE v_current_class_id INT;
DECLARE v_current_stream_id INT;
DECLARE v_next_class_id INT;
DECLARE v_next_stream_id INT;
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
UPDATE promotion_batches
SET status = 'cancelled'
WHERE id = p_batch_id;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Bulk student promotion failed';
END;

SELECT status INTO v_batch_status
FROM promotion_batches
WHERE id = p_batch_id;
IF v_batch_status IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Promotion batch not found';
END IF;
UPDATE promotion_batches
SET status = 'in_progress'
WHERE id = p_batch_id;

SET v_student_count = JSON_LENGTH(p_student_ids);
WHILE v_index < v_student_count DO
SET v_student_id = JSON_UNQUOTE(
    JSON_EXTRACT(p_student_ids, CONCAT('$[', v_index, ']'))
  );

SELECT s.stream_id,
  cs.class_id INTO v_current_stream_id,
  v_current_class_id
FROM students s
  INNER JOIN class_streams cs ON s.stream_id = cs.id
WHERE s.id = v_student_id;

SELECT c_next.id,
  cs_next.id INTO v_next_class_id,
  v_next_stream_id
FROM classes c
  INNER JOIN school_levels sl ON c.level_id = sl.id
  INNER JOIN classes c_next ON c_next.level_id = (sl.id + 1)
  AND c_next.academic_year = p_to_year
  INNER JOIN class_streams cs ON c.id = cs.class_id
  INNER JOIN class_streams cs_next ON cs_next.class_id = c_next.id
  AND cs_next.stream_name = cs.stream_name
WHERE c.id = v_current_class_id
LIMIT 1;

INSERT INTO student_promotions (
    batch_id,
    student_id,
    current_class_id,
    current_stream_id,
    promoted_to_class_id,
    promoted_to_stream_id,
    from_academic_year,
    to_academic_year,
    from_term_id,
    promotion_status
  )
SELECT p_batch_id,
  v_student_id,
  v_current_class_id,
  v_current_stream_id,
  v_next_class_id,
  v_next_stream_id,
  p_from_year,
  p_to_year,
  at.id,
  'pending_approval'
FROM academic_terms at
WHERE at.term_name = 'Term 3'
  AND at.academic_year = p_from_year ON DUPLICATE KEY
UPDATE promotion_status = 'pending_approval';
SET v_index = v_index + 1;
END WHILE;

INSERT INTO class_promotion_queue (
    batch_id,
    class_id,
    stream_id,
    total_in_class,
    approval_status
  )
SELECT DISTINCT p_batch_id,
  sp.promoted_to_class_id,
  sp.promoted_to_stream_id,
  COUNT(*),
  'pending'
FROM student_promotions sp
WHERE sp.batch_id = p_batch_id
GROUP BY sp.promoted_to_class_id,
  sp.promoted_to_stream_id ON DUPLICATE KEY
UPDATE total_in_class =
VALUES(total_in_class);

UPDATE promotion_batches
SET total_students_processed = (
    SELECT COUNT(*)
    FROM student_promotions
    WHERE batch_id = p_batch_id
  ),
  total_pending_approval = (
    SELECT COUNT(*)
    FROM student_promotions
    WHERE batch_id = p_batch_id
      AND promotion_status = 'pending_approval'
  )
WHERE id = p_batch_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_promote_by_grade_bulk` (IN `p_batch_id` INT, IN `p_from_year` INT, IN `p_to_year` INT, IN `p_from_grade` VARCHAR(50), IN `p_to_grade` VARCHAR(50))   BEGIN
    DECLARE v_to_year_id INT;
    DECLARE v_from_year_id INT;
    DECLARE v_to_class_id INT;

    SELECT id INTO v_from_year_id FROM academic_years WHERE year_label = p_from_year LIMIT 1;
    SELECT id INTO v_to_year_id FROM academic_years WHERE year_label = p_to_year LIMIT 1;
    SELECT id INTO v_to_class_id FROM classes WHERE name = p_to_grade LIMIT 1;

    
    INSERT INTO student_promotions (
        student_id, from_academic_year_id, to_academic_year_id,
        from_class_name, to_class_name, promoted_at, status
    )
    SELECT
        ce.student_id,
        v_from_year_id,
        v_to_year_id,
        p_from_grade,
        p_to_grade,
        NOW(),
        'completed'
    FROM class_enrollments ce
    JOIN classes c ON c.id = ce.class_id
    WHERE ce.academic_year_id = v_from_year_id
      AND c.name = p_from_grade
      AND ce.enrollment_status = 'active'
    ON DUPLICATE KEY UPDATE status = 'completed';
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_promote_single_class` (IN `p_batch_id` INT UNSIGNED, IN `p_from_year` YEAR, IN `p_to_year` YEAR, IN `p_current_class_id` INT UNSIGNED, IN `p_current_stream_id` INT UNSIGNED)   BEGIN
DECLARE v_batch_status VARCHAR(50);
DECLARE v_error_msg VARCHAR(255);
DECLARE v_next_level_id INT UNSIGNED;
DECLARE v_next_class_id INT UNSIGNED;
DECLARE v_next_stream_id INT UNSIGNED;
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
UPDATE promotion_batches
SET status = 'cancelled'
WHERE id = p_batch_id;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Single class promotion failed';
END;

SELECT status INTO v_batch_status
FROM promotion_batches
WHERE id = p_batch_id;
IF v_batch_status IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Promotion batch not found';
END IF;

SELECT sl.id INTO v_next_level_id
FROM classes c
  INNER JOIN school_levels sl ON c.level_id = sl.id
WHERE c.id = p_current_class_id;

SELECT c_next.id INTO v_next_class_id
FROM classes c_next
  INNER JOIN class_streams cs_next ON c_next.id = cs_next.class_id
WHERE c_next.level_id = (v_next_level_id + 1)
  AND c_next.academic_year = p_to_year
  AND cs_next.stream_name = (
    SELECT stream_name
    FROM class_streams
    WHERE id = p_current_stream_id
  )
LIMIT 1;

SELECT id INTO v_next_stream_id
FROM class_streams
WHERE class_id = v_next_class_id
  AND stream_name = (
    SELECT stream_name
    FROM class_streams
    WHERE id = p_current_stream_id
  )
LIMIT 1;
IF v_next_class_id IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Next class or stream not found for promotion';
END IF;

IF v_batch_status = 'pending' THEN
UPDATE promotion_batches
SET status = 'in_progress'
WHERE id = p_batch_id;
END IF;

INSERT INTO student_promotions (
    batch_id,
    student_id,
    current_class_id,
    current_stream_id,
    promoted_to_class_id,
    promoted_to_stream_id,
    from_academic_year,
    to_academic_year,
    from_term_id,
    promotion_status
  )
SELECT p_batch_id,
  s.id,
  p_current_class_id,
  p_current_stream_id,
  v_next_class_id,
  v_next_stream_id,
  p_from_year,
  p_to_year,
  at.id,
  'pending_approval'
FROM students s
  INNER JOIN academic_terms at ON at.term_name = 'Term 3'
  AND at.academic_year = p_from_year
WHERE s.stream_id = p_current_stream_id
  AND s.status = 'active'
  AND NOT EXISTS (
    SELECT 1
    FROM student_promotions
    WHERE student_id = s.id
      AND from_academic_year = p_from_year
      AND to_academic_year = p_to_year
  ) ON DUPLICATE KEY
UPDATE promotion_status = 'pending_approval';

INSERT INTO class_promotion_queue (
    batch_id,
    class_id,
    stream_id,
    total_in_class,
    approval_status
  )
VALUES (
    p_batch_id,
    v_next_class_id,
    v_next_stream_id,
    (
      SELECT COUNT(*)
      FROM student_promotions
      WHERE batch_id = p_batch_id
        AND promoted_to_class_id = v_next_class_id
    ),
    'pending'
  ) ON DUPLICATE KEY
UPDATE total_in_class =
VALUES(total_in_class);

UPDATE promotion_batches
SET total_students_processed = (
    SELECT COUNT(*)
    FROM student_promotions
    WHERE batch_id = p_batch_id
  ),
  total_pending_approval = (
    SELECT COUNT(*)
    FROM student_promotions
    WHERE batch_id = p_batch_id
      AND promotion_status = 'pending_approval'
  )
WHERE id = p_batch_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_reallocate_all_payments` ()   BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_student_id INT;
    DECLARE v_total_payments DECIMAL(10,2);
    DECLARE v_remaining DECIMAL(10,2);
    DECLARE v_obligation_id INT;
    DECLARE v_obligation_due DECIMAL(10,2);
    DECLARE v_allocation_amount DECIMAL(10,2);
    
    
    DECLARE student_cursor CURSOR FOR
        SELECT student_id, SUM(amount_paid) as total_payments
        FROM payment_transactions
        WHERE status = 'confirmed'
        GROUP BY student_id;
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    
    TRUNCATE TABLE payment_allocations_detailed;
    
    OPEN student_cursor;
    
    student_loop: LOOP
        FETCH student_cursor INTO v_student_id, v_total_payments;
        
        IF done THEN
            LEAVE student_loop;
        END IF;
        
        SET v_remaining = v_total_payments;
        
        
        BEGIN
            DECLARE obl_done INT DEFAULT FALSE;
            DECLARE obligation_cursor CURSOR FOR
                SELECT id, amount_due
                FROM student_fee_obligations
                WHERE student_id = v_student_id
                  AND amount_paid < amount_due
                ORDER BY due_date ASC, id ASC;
            DECLARE CONTINUE HANDLER FOR NOT FOUND SET obl_done = TRUE;
            
            OPEN obligation_cursor;
            
            allocation_loop:LOOP
                IF v_remaining <= 0 THEN
                    LEAVE allocation_loop;
                END IF;
                
                FETCH obligation_cursor INTO v_obligation_id, v_obligation_due;
                
                IF obl_done THEN
                    LEAVE allocation_loop;
                END IF;
                
                
                SET v_allocation_amount = LEAST(v_remaining, v_obligation_due);
                
                
                UPDATE student_fee_obligations
                SET amount_paid = v_allocation_amount,
                    status = IF(v_allocation_amount >= amount_due, 'paid', 'partial')
                WHERE id = v_obligation_id;
                
                SET v_remaining = v_remaining - v_allocation_amount;
            END LOOP;
            
            CLOSE obligation_cursor;
        END;
        
        
        
        
    END LOOP;
    
    CLOSE student_cursor;
    
    
    UPDATE student_fee_obligations
    SET status = 'pending'
    WHERE amount_paid = 0;
    
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_record_assessment_change` (IN `p_assessment_result_id` INT UNSIGNED, IN `p_student_id` INT UNSIGNED, IN `p_assessment_id` INT UNSIGNED, IN `p_old_marks` DECIMAL(6,2), IN `p_new_marks` DECIMAL(6,2), IN `p_reason` VARCHAR(255), IN `p_changed_by` INT UNSIGNED)   BEGIN
DECLARE v_old_grade VARCHAR(4);
DECLARE v_new_grade VARCHAR(4);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Error recording assessment change';
END;

SET v_old_grade = calculate_grade(p_old_marks);
SET v_new_grade = calculate_grade(p_new_marks);

INSERT INTO assessment_history (
    assessment_result_id,
    student_id,
    assessment_id,
    old_marks,
    new_marks,
    old_grade,
    new_grade,
    change_reason,
    changed_by
  )
VALUES (
    p_assessment_result_id,
    p_student_id,
    p_assessment_id,
    p_old_marks,
    p_new_marks,
    v_old_grade,
    v_new_grade,
    p_reason,
    p_changed_by
  );

UPDATE assessment_results
SET marks_obtained = p_new_marks,
  grade = v_new_grade,
  points = calculate_points(p_new_marks),
  updated_at = NOW()
WHERE id = p_assessment_result_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_record_cash_payment` (IN `p_student_id` INT, IN `p_amount` DECIMAL(10,2), IN `p_payment_method` VARCHAR(50), IN `p_payment_date` DATETIME)   BEGIN
    DECLARE v_year YEAR;
    DECLARE v_term_id INT;

    SELECT year_label INTO v_year FROM academic_years WHERE is_current = 1 LIMIT 1;
    SELECT id INTO v_term_id FROM academic_terms WHERE is_current = 1 LIMIT 1;

