END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_record_transport_payment` (IN `p_student_id` INT, IN `p_amount` DECIMAL(10,2), IN `p_month` INT, IN `p_year` INT, IN `p_payment_date` DATETIME, IN `p_payment_method` VARCHAR(50), IN `p_transaction_id` VARCHAR(100))   BEGIN
