CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_refresh_student_payment_summary` (IN `p_student_id` INT, IN `p_year` INT, IN `p_term_id` INT)   BEGIN
    
    INSERT INTO student_payment_history_summary (
        student_id, academic_year, term_id,
        total_paid, total_balance, last_payment_date
    )
    SELECT
        p_student_id,
        p_year,
        p_term_id,
        COALESCE(SUM(CASE WHEN status = 'confirmed' THEN amount_paid ELSE 0 END), 0),
        COALESCE((
            SELECT sfb.balance FROM student_fee_balances sfb
            WHERE sfb.student_id = p_student_id LIMIT 1
        ), 0),
        MAX(payment_date)
    FROM payment_transactions
    WHERE student_id = p_student_id
      AND term_id = p_term_id
      AND academic_year = p_year
    ON DUPLICATE KEY UPDATE
        total_paid = VALUES(total_paid),
        total_balance = VALUES(total_balance),
        last_payment_date = VALUES(last_payment_date),
        updated_at = NOW();
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_register_uniform_sale` (IN `p_student_id` INT, IN `p_item_id` INT, IN `p_quantity` INT, IN `p_unit_price` DECIMAL(10,2), IN `p_total_amount` DECIMAL(10,2), IN `p_recorded_by` INT, IN `p_sale_date` DATE)   BEGIN
