CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_return_allocation` (IN `p_allocation_id` INT UNSIGNED, IN `p_returned_quantity` INT, IN `p_returned_condition` VARCHAR(100))   BEGIN
DECLARE v_error_msg VARCHAR(255);
DECLARE v_allocated_quantity INT;
DECLARE v_item_id INT UNSIGNED;
DECLARE v_status VARCHAR(50);
DECLARE v_msg VARCHAR(255);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = v_error_msg;
END;
SELECT item_id,
  allocated_quantity,
  status INTO v_item_id,
  v_allocated_quantity,
  v_status
FROM inventory_allocations
WHERE id = p_allocation_id;
IF v_item_id IS NULL THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Allocation not found';
END IF;
IF p_returned_quantity > v_allocated_quantity THEN
    SET v_msg = CONCAT('Return quantity exceeds allocated (', v_allocated_quantity, ')');
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_msg;
END IF;

UPDATE inventory_allocations
SET returned_quantity = p_returned_quantity,
  returned_at = NOW(),
  status = IF(
    p_returned_quantity = v_allocated_quantity,
    'fully_returned',
    'partially_returned'
  ),
  updated_at = NOW()
WHERE id = p_allocation_id;
UPDATE inventory_items
SET current_quantity = current_quantity + p_returned_quantity
WHERE id = v_item_id;
INSERT INTO inventory_transactions (
    item_id,
    transaction_type,
    quantity,
    transaction_date,
    created_at,
    reference_type,
    reference_id,
    notes
  )
VALUES (
    v_item_id,
    'in',
    p_returned_quantity,
    CURDATE(),
    NOW(),
    'allocation_return',
    p_allocation_id,
    CONCAT(
      'Allocation returned - Condition: ',
      p_returned_condition
    )
  );
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'allocation_returned',
    JSON_OBJECT(
      'allocation_id',
      p_allocation_id,
      'quantity',
      p_returned_quantity
    ),
    NOW()
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_revoke_permission` (IN `p_user_id` INT UNSIGNED, IN `p_permission_code` VARCHAR(255), IN `p_reason` VARCHAR(255), IN `p_changed_by` INT UNSIGNED, OUT `p_success` TINYINT)  MODIFIES SQL DATA BEGIN
    DECLARE perm_id INT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        SET p_success = 0;
    END;
    
    
    SELECT id INTO perm_id FROM permissions WHERE code = p_permission_code LIMIT 1;
    
    IF perm_id IS NULL THEN
        SET p_success = 0;
    ELSE
        DELETE FROM user_permissions
        WHERE user_id = p_user_id AND permission_id = perm_id;
        
        
        IF EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.TABLES 
            WHERE TABLE_SCHEMA = 'KingsWayAcademy' AND TABLE_NAME = 'permission_audit_log') THEN
            INSERT INTO permission_audit_log (action, user_id, permission_id, changed_by, reason)
            VALUES ('revoke_permission', p_user_id, perm_id, p_changed_by, p_reason);
        END IF;
        
        SET p_success = 1;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_revoke_role` (IN `p_user_id` INT UNSIGNED, IN `p_role_name` VARCHAR(50), IN `p_reason` VARCHAR(255), IN `p_changed_by` INT UNSIGNED, OUT `p_success` TINYINT)  MODIFIES SQL DATA BEGIN
    DECLARE role_id INT UNSIGNED;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        SET p_success = 0;
    END;
    
    
    SELECT id INTO role_id FROM roles WHERE name = p_role_name LIMIT 1;
    
    IF role_id IS NULL THEN
        SET p_success = 0;
    ELSE
        DELETE FROM user_roles WHERE user_id = p_user_id AND role_id = role_id;
        
        
        IF EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.TABLES 
            WHERE TABLE_SCHEMA = 'KingsWayAcademy' AND TABLE_NAME = 'permission_audit_log') THEN
            INSERT INTO permission_audit_log (action, user_id, role_id, changed_by, reason)
            VALUES ('revoke_role', p_user_id, role_id, p_changed_by, p_reason);
        END IF;
        
        SET p_success = 1;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_schedule_discipline_hearing` (IN `p_case_id` INT UNSIGNED, IN `p_hearing_date` DATETIME, IN `p_panel_members` JSON, IN `p_scheduled_by` INT UNSIGNED)   BEGIN
    DECLARE v_student_id INT UNSIGNED;
    
    START TRANSACTION;
    
    
    SELECT student_id INTO v_student_id
    FROM student_discipline
    WHERE id = p_case_id;
    
    
    INSERT INTO discipline_hearings (
        case_id,
        student_id,
        hearing_date,
        panel_members,
        scheduled_by,
        status
    ) VALUES (
        p_case_id,
        v_student_id,
        p_hearing_date,
        p_panel_members,
        p_scheduled_by,
        'scheduled'
    );
    
    
    UPDATE student_discipline
    SET status = 'hearing_scheduled'
    WHERE id = p_case_id;
    
    
    CALL sp_send_internal_message(
        p_panel_members,
        'Discipline Hearing Scheduled',
        CONCAT('You are scheduled for a discipline hearing on ', p_hearing_date),
        p_scheduled_by
    );
    
    COMMIT;
END$$

