CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_send_fee_reminder` (IN `p_student_id` INT)   BEGIN
    DECLARE v_balance DECIMAL(10,2) DEFAULT 0.00;

    SELECT COALESCE(balance, 0) INTO v_balance
    FROM student_fee_balances
    WHERE student_id = p_student_id LIMIT 1;

    IF v_balance > 0 THEN
        INSERT INTO fee_reminders (
            student_id, amount_due, reminder_date, status
        ) VALUES (
            p_student_id, v_balance, CURDATE(), 'sent'
        );
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_send_fee_reminders` ()   BEGIN
    
    INSERT INTO fee_reminders (student_id, amount_due, reminder_date, status)
    SELECT student_id, balance, CURDATE(), 'queued'
    FROM student_fee_balances
    WHERE balance > 0;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_send_internal_message` (IN `p_sender_id` INT UNSIGNED, IN `p_recipient_ids` VARCHAR(1000), IN `p_subject` VARCHAR(255), IN `p_body` LONGTEXT, IN `p_priority` VARCHAR(20), IN `p_message_type` VARCHAR(50), IN `p_conversation_id` INT UNSIGNED)   BEGIN
DECLARE v_error_msg VARCHAR(255);
DECLARE v_message_id INT UNSIGNED;
DECLARE v_conversation_id INT UNSIGNED;
DECLARE v_recipient_count INT;
DECLARE v_idx INT DEFAULT 1;
DECLARE v_recipient_id INT UNSIGNED;
DECLARE v_temp_id VARCHAR(20);
DECLARE v_remaining VARCHAR(1000);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = v_error_msg;
END;

IF p_conversation_id IS NULL THEN
INSERT INTO internal_conversations (
    title,
    conversation_type,
    created_by,
    created_at,
    updated_at
  )
VALUES (
    p_subject,
    p_message_type,
    p_sender_id,
    NOW(),
    NOW()
  );
SET v_conversation_id = LAST_INSERT_ID();
ELSE
SET v_conversation_id = p_conversation_id;
END IF;

INSERT INTO internal_messages (
    conversation_id,
    sender_id,
    subject,
    body,
    priority,
    message_type,
    created_at
  )
VALUES (
    v_conversation_id,
    p_sender_id,
    p_subject,
    p_body,
    p_priority,
    p_message_type,
    NOW()
  );
SET v_message_id = LAST_INSERT_ID();

INSERT IGNORE INTO conversation_participants (conversation_id, user_id, added_by, joined_at)
VALUES (
    v_conversation_id,
    p_sender_id,
    p_sender_id,
    NOW()
  );

SET v_remaining = CONCAT(p_recipient_ids, ',');
WHILE LOCATE(',', v_remaining) > 0 DO
SET v_temp_id = TRIM(SUBSTRING_INDEX(v_remaining, ',', 1));
SET v_recipient_id = CAST(v_temp_id AS UNSIGNED);
IF v_recipient_id > 0 THEN
INSERT IGNORE INTO conversation_participants (conversation_id, user_id, added_by, joined_at)
VALUES (
    v_conversation_id,
    v_recipient_id,
    p_sender_id,
    NOW()
  );
INSERT INTO message_read_status (message_id, recipient_id, status, created_at)
VALUES (v_message_id, v_recipient_id, 'unread', NOW());
UPDATE conversation_participants
SET unread_count = unread_count + 1
WHERE conversation_id = v_conversation_id
  AND user_id = v_recipient_id;
END IF;
SET v_remaining = SUBSTRING(v_remaining, LOCATE(',', v_remaining) + 1);
END WHILE;
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'internal_message_sent',
    JSON_OBJECT(
      'message_id',
      v_message_id,
      'sender_id',
      p_sender_id,
      'conversation_id',
      v_conversation_id
    ),
    NOW()
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_send_sms_to_parents` (IN `p_parent_ids` TEXT, IN `p_message` TEXT, IN `p_template_id` INT, IN `p_message_type` VARCHAR(50), IN `p_sent_by` INT)   BEGIN
    
    INSERT INTO sms_communications (
        sender_id, recipient_ids, message, message_type, status, created_at
    ) VALUES (
        p_sent_by,
        p_parent_ids,
        p_message,
        COALESCE(p_message_type, 'general'),
        'queued',
        NOW()
    );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_suspend_student_promotion` (IN `p_promotion_id` INT UNSIGNED, IN `p_suspension_type` VARCHAR(50), IN `p_suspension_reason` TEXT, IN `p_expected_return` DATE, IN `p_suspended_by` INT UNSIGNED)   BEGIN
DECLARE v_student_id INT UNSIGNED;
DECLARE v_to_academic_year YEAR;
DECLARE v_error_msg VARCHAR(255);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Suspension failed';
END;

SELECT student_id,
  to_academic_year INTO v_student_id,
  v_to_academic_year
FROM student_promotions
WHERE id = p_promotion_id;

UPDATE student_promotions
SET promotion_status = 'suspended'
WHERE id = p_promotion_id;

INSERT INTO student_suspensions (
    student_id,
    academic_year,
    suspension_type,
    reason,
    suspension_date,
    expected_return_date,
    suspended_by,
    status
  )
VALUES (
    v_student_id,
    v_to_academic_year,
    p_suspension_type,
    p_suspension_reason,
    NOW(),
    p_expected_return,
    p_suspended_by,
    'active'
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_track_student_behavior` (IN `p_student_id` INT UNSIGNED, IN `p_observation_date` DATE, IN `p_behavior_rating` ENUM('excellent','good','satisfactory','needs_improvement','poor'), IN `p_notes` TEXT, IN `p_recorded_by` INT UNSIGNED)   BEGIN
    DECLARE v_term_id INT UNSIGNED;
    DECLARE v_academic_year YEAR;
    
    
    SELECT id, year INTO v_term_id, v_academic_year
    FROM academic_terms
    WHERE status = 'active'
    LIMIT 1;
    
    
    INSERT INTO conduct_tracking (
        student_id,
        academic_year,
        term_id,
        conduct_rating,
        conduct_comments,
        teacher_notes,
        recorded_by,
        recorded_date
    ) VALUES (
        p_student_id,
        v_academic_year,
        v_term_id,
        p_behavior_rating,
        p_notes,
        p_notes,
        p_recorded_by,
        p_observation_date
    )
    ON DUPLICATE KEY UPDATE
        conduct_rating = p_behavior_rating,
        conduct_comments = CONCAT(conduct_comments, '\n', p_observation_date, ': ', p_notes),
        teacher_notes = CONCAT(teacher_notes, '\n', p_observation_date, ': ', p_notes),
        updated_at = NOW();
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_transfer_student_promotion` (IN `p_promotion_id` INT UNSIGNED, IN `p_transfer_school` VARCHAR(255), IN `p_transfer_reason` TEXT, IN `p_processed_by` INT UNSIGNED)   BEGIN
DECLARE v_student_id INT UNSIGNED;
DECLARE v_error_msg VARCHAR(255);
DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Transfer failed';
END;

SELECT student_id INTO v_student_id
FROM student_promotions
WHERE id = p_promotion_id;

UPDATE student_promotions
SET promotion_status = 'transferred',
  transfer_to_school = p_transfer_school,
  promotion_reason = p_transfer_reason,
  approved_by = p_processed_by,
  approval_date = NOW()
WHERE id = p_promotion_id;

UPDATE students
SET status = 'transferred'
WHERE id = v_student_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_transition_to_new_academic_year` (IN `p_current_year` INT, IN `p_new_year` INT)   BEGIN
    
    UPDATE academic_years SET is_current = 0 WHERE id = p_current_year;
    
    UPDATE academic_years SET is_current = 1 WHERE id = p_new_year;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_transition_to_new_term` (IN `p_current_term` INT, IN `p_new_term` INT)   BEGIN
    
    UPDATE academic_terms SET is_current = 0 WHERE id = p_current_term;
    
    UPDATE academic_terms SET is_current = 1 WHERE id = p_new_term;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_unlink_parent_from_student` (IN `p_parent_id` INT, IN `p_student_id` INT, OUT `p_success` TINYINT)   BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET p_success = 0;
    END;

    DELETE FROM student_parents
    WHERE parent_id = p_parent_id AND student_id = p_student_id;

    SET p_success = ROW_COUNT() > 0;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_unlock_user_account` (IN `p_user_id` INT UNSIGNED, IN `p_unlocked_by` INT UNSIGNED, IN `p_unlock_reason` TEXT)   BEGIN
DECLARE v_locked_date DATETIME;
SELECT locked_date INTO v_locked_date
FROM user_login_attempts
WHERE username = (
    SELECT username
    FROM users
    WHERE id = p_user_id
  )
ORDER BY attempt_time DESC
LIMIT 1;
UPDATE users
SET status = 'active'
WHERE id = p_user_id;
INSERT INTO account_unlock_history (
    user_id,
    locked_date,
    unlocked_date,
    unlocked_by,
    unlock_reason
  )
VALUES (
    p_user_id,
    COALESCE(v_locked_date, NOW()),
    NOW(),
    p_unlocked_by,
    p_unlock_reason
  );
INSERT INTO system_events (event_type, event_data)
VALUES (
    'account_unlocked',
    JSON_OBJECT(
      'user_id',
      p_user_id,
      'unlocked_by',
      p_unlocked_by
    )
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_update_kpi_achievement` (IN `p_staff_id` INT UNSIGNED, IN `p_kpi_definition_id` INT UNSIGNED, IN `p_academic_year` INT, IN `p_achieved_value` DECIMAL(10,2), IN `p_recorded_by` INT UNSIGNED, IN `p_notes` TEXT)   BEGIN
DECLARE v_target_value DECIMAL(10, 2);
SELECT kt.target_value INTO v_target_value
FROM kpi_targets kt
WHERE kt.staff_id = p_staff_id
  AND kt.kpi_definition_id = p_kpi_definition_id
  AND kt.academic_year = p_academic_year
  AND kt.is_active = 1;
INSERT INTO kpi_achievements (
    staff_id,
    kpi_definition_id,
    academic_year,
    achieved_value,
    achievement_date,
    recorded_by,
    notes
  )
VALUES (
    p_staff_id,
    p_kpi_definition_id,
    p_academic_year,
    p_achieved_value,
    CURDATE(),
    p_recorded_by,
    p_notes
  );
INSERT INTO system_events (event_type, event_data)
VALUES (
    'kpi_achievement_recorded',
    JSON_OBJECT(
      'staff_id',
      p_staff_id,
      'kpi_id',
      p_kpi_definition_id,
      'achieved',
      p_achieved_value,
      'target',
      v_target_value
    )
  );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_update_parent` (IN `p_parent_id` INT, IN `p_first_name` VARCHAR(50), IN `p_middle_name` VARCHAR(50), IN `p_last_name` VARCHAR(50), IN `p_id_number` VARCHAR(20), IN `p_gender` VARCHAR(10), IN `p_date_of_birth` DATE, IN `p_phone_1` VARCHAR(20), IN `p_phone_2` VARCHAR(20), IN `p_email` VARCHAR(100), IN `p_occupation` VARCHAR(100), IN `p_address` TEXT, OUT `p_success` TINYINT)   BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET p_success = 0;
    END;

    UPDATE users
    SET
        first_name = COALESCE(p_first_name, first_name),
        last_name = COALESCE(p_last_name, last_name),
        email = COALESCE(p_email, email),
        updated_at = NOW()
    WHERE id = p_parent_id;

    SET p_success = ROW_COUNT() > 0;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_users_with_multiple_roles` ()   BEGIN
    SELECT u.id, u.username, u.email, u.first_name, u.last_name,
           COUNT(ur.role_id) AS role_count
    FROM users u
    JOIN user_roles ur ON ur.user_id = u.id
    GROUP BY u.id, u.username, u.email, u.first_name, u.last_name
    HAVING role_count > 1;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_users_with_permission` (IN `p_permission_code` VARCHAR(255))   BEGIN
    SELECT DISTINCT u.id, u.username, u.email, u.first_name, u.last_name
    FROM users u
    JOIN v_user_permissions_effective vupe ON vupe.user_id = u.id
    WHERE vupe.permission_code = p_permission_code
      AND u.status = 'active';
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_users_with_role` (IN `p_role_id` INT)   BEGIN
    SELECT u.id, u.username, u.email, u.first_name, u.last_name, u.status
    FROM users u
    JOIN user_roles ur ON ur.user_id = u.id
    WHERE ur.role_id = p_role_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_users_with_temporary_permissions` ()   BEGIN
    SELECT DISTINCT u.id, u.username, u.email, u.first_name, u.last_name,
           up.expires_at, p.code AS permission_code
    FROM users u
    JOIN user_permissions up ON up.user_id = u.id
    JOIN permissions p ON p.id = up.permission_id
    WHERE up.expires_at IS NOT NULL
      AND up.expires_at > NOW()
      AND up.permission_type IN ('grant', 'override');
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_user_get_denied_permissions` (IN `p_user_id` INT)   BEGIN
    SELECT DISTINCT p.code AS permission_code
    FROM user_permissions up
    JOIN permissions p ON p.id = up.permission_id
    WHERE up.user_id = p_user_id
      AND up.permission_type = 'deny'
      AND (up.expires_at IS NULL OR up.expires_at > NOW());
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_user_get_effective_permissions` (IN `p_user_id` INT)   BEGIN
    
    
    
    SELECT DISTINCT permission_code
    FROM v_user_permissions_effective
    WHERE user_id = p_user_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_user_get_permissions_by_entity` (IN `p_user_id` INT)   BEGIN
    SELECT DISTINCT p.code AS permission_code, p.entity, p.action, p.module
    FROM v_user_permissions_effective vupe
    JOIN permissions p ON p.code = vupe.permission_code
    WHERE vupe.user_id = p_user_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_user_get_permission_summary` (IN `p_user_id` INT)   BEGIN
    SELECT
        p.module,
        COUNT(DISTINCT p.id) AS permission_count,
        GROUP_CONCAT(DISTINCT p.action ORDER BY p.action SEPARATOR ',') AS actions
    FROM v_user_permissions_effective vupe
    JOIN permissions p ON p.code = vupe.permission_code
    WHERE vupe.user_id = p_user_id
    GROUP BY p.module;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_user_get_roles_detailed` (IN `p_user_id` INT)   BEGIN
    SELECT r.id, r.name, r.description
    FROM user_roles ur
    JOIN roles r ON r.id = ur.role_id
    WHERE ur.user_id = p_user_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_validate_payment_request` (IN `p_admission_number` VARCHAR(50), IN `p_amount` DECIMAL(10,2), IN `p_transaction_ref` VARCHAR(100))   BEGIN
    DECLARE v_student_id INT UNSIGNED;
    DECLARE v_student_name VARCHAR(200);
    DECLARE v_student_status VARCHAR(50);
    DECLARE v_current_balance DECIMAL(10, 2);
    DECLARE v_duplicate_count INT;
    
    
    SELECT 
        s.id,
        CONCAT(s.first_name, ' ', s.last_name),
        s.status,
        COALESCE(sfb.balance, 0)
    INTO 
        v_student_id,
        v_student_name,
        v_student_status,
        v_current_balance
    FROM students s
    LEFT JOIN student_fee_balances sfb ON s.id = sfb.student_id
    WHERE s.admission_no = p_admission_number
    LIMIT 1;
    
    
    IF p_transaction_ref IS NOT NULL THEN
        SELECT COUNT(*) INTO v_duplicate_count
        FROM mpesa_transactions
        WHERE mpesa_code = p_transaction_ref;
    ELSE
        SET v_duplicate_count = 0;
    END IF;
    
    
    SELECT 
        CASE 
            WHEN v_student_id IS NULL THEN 'INVALID_ADMISSION'
            WHEN v_student_status NOT IN ('active', 'enrolled') THEN 'INACTIVE_STUDENT'
            WHEN v_duplicate_count > 0 THEN 'DUPLICATE_TRANSACTION'
            WHEN p_amount <= 0 THEN 'INVALID_AMOUNT'
            ELSE 'VALID'
        END AS validation_result,
        v_student_id AS student_id,
        p_admission_number AS admission_number,
        v_student_name AS student_name,
        v_student_status AS student_status,
        v_current_balance AS current_balance,
        p_amount AS payment_amount,
        v_duplicate_count AS duplicate_count;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_validate_staff_assignment` (IN `p_staff_id` INT, IN `p_position_id` INT, IN `p_department_id` INT, IN `p_effective_date` DATE, OUT `p_is_valid` TINYINT, OUT `p_error_message` VARCHAR(255))   BEGIN
    DECLARE v_staff_exists INT DEFAULT 0;
    DECLARE v_dept_exists INT DEFAULT 0;

    SELECT COUNT(*) INTO v_staff_exists FROM staff WHERE id = p_staff_id AND status = 'active';
    SELECT COUNT(*) INTO v_dept_exists FROM departments WHERE id = p_department_id;

    IF v_staff_exists = 0 THEN
        SET p_is_valid = 0;
        SET p_error_message = 'Staff member not found or inactive';
    ELSEIF v_dept_exists = 0 THEN
        SET p_is_valid = 0;
        SET p_error_message = 'Department not found';
    ELSE
        SET p_is_valid = 1;
        SET p_error_message = '';
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_validate_term_holiday_conflicts` (IN `p_start_date` DATE, IN `p_end_date` DATE)   BEGIN
    SELECT
        sc.event_name,
        sc.start_date,
        sc.end_date,
        'conflict' AS conflict_type
    FROM school_calendar sc
    WHERE sc.start_date <= p_end_date
      AND sc.end_date >= p_start_date
      AND sc.event_type IN ('holiday', 'term_break', 'exam')
    ORDER BY sc.start_date;
END$$

--
-- Functions
--
CREATE DEFINER=`root`@`localhost` FUNCTION `calculate_class_average` (`p_class_id` INT UNSIGNED, `p_subject_id` INT UNSIGNED, `p_term_id` INT UNSIGNED) RETURNS DECIMAL(10,2) DETERMINISTIC BEGIN
DECLARE avg_marks DECIMAL(10, 2);
SELECT AVG(ar.marks_obtained) INTO avg_marks
FROM assessment_results ar
  JOIN assessments a ON ar.assessment_id = a.id
  JOIN students s ON ar.student_id = s.id
  JOIN class_streams cs ON s.stream_id = cs.id
WHERE cs.class_id = p_class_id
  AND a.subject_id = p_subject_id
  AND a.term_id = p_term_id;
RETURN COALESCE(avg_marks, 0.00);
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `calculate_grade` (`marks` DECIMAL(5,2)) RETURNS VARCHAR(4) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci DETERMINISTIC BEGIN RETURN CASE
  WHEN marks BETWEEN 90 AND 100 THEN 'EE1' 
  WHEN marks BETWEEN 75 AND 89 THEN 'EE2' 
  WHEN marks BETWEEN 58 AND 74 THEN 'ME1' 
  WHEN marks BETWEEN 41 AND 57 THEN 'ME2' 
  WHEN marks BETWEEN 31 AND 40 THEN 'AE1' 
  WHEN marks BETWEEN 21 AND 30 THEN 'AE2' 
  WHEN marks BETWEEN 11 AND 20 THEN 'BE1' 
  WHEN marks BETWEEN 1 AND 10 THEN 'BE2' 
  ELSE NULL
END;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `calculate_points` (`marks` DECIMAL(5,2)) RETURNS DECIMAL(3,1) DETERMINISTIC BEGIN RETURN CASE
  WHEN marks BETWEEN 90 AND 100 THEN 4.0
  WHEN marks BETWEEN 75 AND 89 THEN 3.5
  WHEN marks BETWEEN 58 AND 74 THEN 3.0
  WHEN marks BETWEEN 41 AND 57 THEN 2.5
  WHEN marks BETWEEN 31 AND 40 THEN 2.0
  WHEN marks BETWEEN 21 AND 30 THEN 1.5
  WHEN marks BETWEEN 11 AND 20 THEN 1.0
  WHEN marks BETWEEN 1 AND 10 THEN 0.5
  ELSE 0.0
END;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `calculate_student_age` (`date_of_birth` DATE) RETURNS INT(11) DETERMINISTIC BEGIN RETURN TIMESTAMPDIFF(YEAR, date_of_birth, CURDATE());
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `calculate_term_fees` (`p_student_id` INT UNSIGNED, `p_term_id` INT UNSIGNED) RETURNS DECIMAL(10,2) READS SQL DATA BEGIN
DECLARE total_fees DECIMAL(10, 2);
SELECT COALESCE(SUM(fs.amount), 0) INTO total_fees
FROM fee_structures fs
  JOIN student_fee_balances sfb ON fs.id = sfb.fee_structure_id
WHERE sfb.student_id = p_student_id
  AND sfb.academic_term_id = p_term_id;
RETURN total_fees;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_get_batch_approval_percentage` (`p_batch_id` INT UNSIGNED) RETURNS DECIMAL(5,2) DETERMINISTIC READS SQL DATA BEGIN
DECLARE v_total INT;
DECLARE v_approved INT;
SELECT COUNT(*) INTO v_total
FROM student_promotions
WHERE batch_id = p_batch_id;
IF v_total = 0 THEN RETURN 0.00;
END IF;
SELECT COUNT(*) INTO v_approved
FROM student_promotions
WHERE batch_id = p_batch_id
  AND promotion_status = 'approved';
RETURN ROUND((v_approved / v_total) * 100, 2);
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_get_child_discount_rate` (`p_staff_id` INT UNSIGNED, `p_student_id` INT UNSIGNED) RETURNS DECIMAL(5,2) DETERMINISTIC BEGIN
    DECLARE v_child_order INT DEFAULT 1;
    DECLARE v_discount DECIMAL(5,2);
    DECLARE v_first_discount DECIMAL(5,2);
    DECLARE v_second_discount DECIMAL(5,2);
    DECLARE v_third_discount DECIMAL(5,2);
    
    
    SELECT CAST(config_value AS DECIMAL(5,2)) INTO v_first_discount 
    FROM staff_child_fee_config WHERE config_key = 'first_child_discount_percentage' AND is_active = 1;
    
    SELECT CAST(config_value AS DECIMAL(5,2)) INTO v_second_discount 
    FROM staff_child_fee_config WHERE config_key = 'second_child_discount_percentage' AND is_active = 1;
    
    SELECT CAST(config_value AS DECIMAL(5,2)) INTO v_third_discount 
    FROM staff_child_fee_config WHERE config_key = 'third_child_discount_percentage' AND is_active = 1;
    
    
    SET v_first_discount = IFNULL(v_first_discount, 50.00);
    SET v_second_discount = IFNULL(v_second_discount, 40.00);
    SET v_third_discount = IFNULL(v_third_discount, 30.00);
    
    
    SELECT COUNT(*) + 1 INTO v_child_order
    FROM staff_children sc
    JOIN students st ON sc.student_id = st.id
    WHERE sc.staff_id = p_staff_id 
    AND sc.student_id < p_student_id
    AND sc.fee_deduction_enabled = 1
    AND st.status = 'active';
    
    
    SET v_discount = CASE 
        WHEN v_child_order = 1 THEN v_first_discount
        WHEN v_child_order = 2 THEN v_second_discount
        ELSE v_third_discount
    END;
    
    RETURN v_discount;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_get_parent_children_count` (`p_parent_id` INT UNSIGNED) RETURNS INT(11) DETERMINISTIC READS SQL DATA BEGIN
    DECLARE v_count INT DEFAULT 0;
    
    SELECT COUNT(DISTINCT student_id) 
    INTO v_count
    FROM student_parents 
    WHERE parent_id = p_parent_id;
    
    RETURN v_count;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_get_parent_total_fee_balance` (`p_parent_id` INT UNSIGNED) RETURNS DECIMAL(12,2) DETERMINISTIC READS SQL DATA BEGIN
    DECLARE v_total DECIMAL(12,2) DEFAULT 0;
    
    SELECT COALESCE(SUM(sfb.balance), 0)
    INTO v_total
    FROM student_fee_balances sfb
    JOIN student_parents sp ON sfb.student_id = sp.student_id
    WHERE sp.parent_id = p_parent_id;
    
    RETURN v_total;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_get_student_promotion_status` (`p_student_id` INT UNSIGNED, `p_from_year` YEAR, `p_to_year` YEAR) RETURNS VARCHAR(50) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci DETERMINISTIC READS SQL DATA BEGIN
DECLARE v_status VARCHAR(50);
SELECT promotion_status INTO v_status
FROM student_promotions
WHERE student_id = p_student_id
  AND from_academic_year = p_from_year
  AND to_academic_year = p_to_year
LIMIT 1;
RETURN IFNULL(v_status, 'no_promotion');
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_has_permission` (`p_user_id` INT UNSIGNED, `p_permission_code` VARCHAR(255)) RETURNS TINYINT(1) READS SQL DATA BEGIN
    DECLARE has_perm TINYINT(1);
    
    
    SET has_perm = (SELECT COUNT(*) > 0
        FROM user_roles ur
        JOIN role_permissions rp ON ur.role_id = rp.role_id
        JOIN permissions p ON rp.permission_id = p.id
        WHERE ur.user_id = p_user_id AND p.code = p_permission_code);
    
    IF has_perm THEN
        RETURN 1;
    END IF;
    
    
    IF EXISTS(
        SELECT 1 FROM user_permissions up
        JOIN permissions p ON up.permission_id = p.id
        WHERE up.user_id = p_user_id 
            AND p.code = p_permission_code
            AND up.permission_type = 'deny'
            AND (up.expires_at IS NULL OR up.expires_at > NOW())
    ) THEN
        RETURN 0;
    END IF;
    
    
    SET has_perm = (SELECT COUNT(*) > 0
        FROM user_permissions up
        JOIN permissions p ON up.permission_id = p.id
        WHERE up.user_id = p_user_id 
            AND p.code = p_permission_code
            AND up.permission_type IN ('grant', 'override')
            AND (up.expires_at IS NULL OR up.expires_at > NOW()));
    
    RETURN IF(has_perm, 1, 0);
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_is_school_day` (`check_date` DATE) RETURNS TINYINT(1) DETERMINISTIC BEGIN
    DECLARE is_school BOOLEAN DEFAULT TRUE;
    DECLARE day_type_val VARCHAR(50);
    
    
    SELECT day_type INTO day_type_val FROM school_calendar WHERE date = check_date;
    
    IF day_type_val IN ('public_holiday', 'school_holiday', 'weekend') THEN
        SET is_school = FALSE;
    ELSEIF day_type_val IS NULL AND DAYOFWEEK(check_date) IN (1, 7) THEN
        
        SET is_school = FALSE;
    END IF;
    
    RETURN is_school;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_is_student_suspended` (`p_student_id` INT UNSIGNED, `p_academic_year` YEAR) RETURNS TINYINT(1) DETERMINISTIC READS SQL DATA BEGIN
DECLARE v_is_suspended TINYINT(1);
SELECT IF(COUNT(*) > 0, 1, 0) INTO v_is_suspended
FROM student_suspensions
WHERE student_id = p_student_id
  AND academic_year = p_academic_year
  AND status IN ('active', 'pending');
RETURN v_is_suspended;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_notify_low_stock` (`p_item_id` INT) RETURNS VARCHAR(255) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci DETERMINISTIC BEGIN
DECLARE v_message VARCHAR(255);
DECLARE v_qty INT;
DECLARE v_min INT;
SELECT current_quantity,
  minimum_quantity INTO v_qty,
  v_min
FROM inventory_items
WHERE id = p_item_id;
IF v_qty <= v_min THEN
SET v_message = CONCAT('Low stock alert for item ', p_item_id);
ELSE
SET v_message = '';
END IF;
RETURN v_message;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_staff_expected_today` (`p_staff_id` INT, `p_date` DATE) RETURNS VARCHAR(50) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci DETERMINISTIC BEGIN
    DECLARE result VARCHAR(50) DEFAULT 'expected';
    DECLARE leave_count INT;
    DECLARE off_day_count INT;
    
    
    SELECT COUNT(*) INTO leave_count 
    FROM staff_leaves 
    WHERE staff_id = p_staff_id 
        AND p_date BETWEEN start_date AND end_date
        AND status = 'approved';
    
    IF leave_count > 0 THEN
        RETURN 'on_leave';
    END IF;
    
    
    SELECT COUNT(*) INTO off_day_count
    FROM staff_duty_roster sdr
    JOIN staff_duty_types sdt ON sdr.duty_type_id = sdt.id
    WHERE sdr.staff_id = p_staff_id 
        AND sdr.date = p_date
        AND sdt.code IN ('OFF', 'WEEKEND_OFF');
    
    IF off_day_count > 0 THEN
        RETURN 'off_day';
    END IF;
    
    
    SELECT COUNT(*) INTO off_day_count
    FROM staff_off_day_patterns
    WHERE staff_id = p_staff_id
        AND day_of_week = DAYNAME(p_date)
        AND is_off = TRUE
        AND p_date >= effective_from
        AND (effective_to IS NULL OR p_date <= effective_to);
    
    IF off_day_count > 0 THEN
        RETURN 'pattern_off';
    END IF;
    
    RETURN result;
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `fn_student_fee_due` (`p_student_id` INT, `p_term_id` INT) RETURNS DECIMAL(10,2) DETERMINISTIC BEGIN
