CREATE DEFINER=`root`@`localhost` FUNCTION `fn_user_has_permission` (`p_user_id` INT UNSIGNED, `p_permission_code` VARCHAR(255)) RETURNS TINYINT(1) READS SQL DATA COMMENT 'Returns 1 if user has permission, 0 otherwise (checks denials, expiration, etc)' BEGIN
    DECLARE perm_id INT;
    DECLARE has_perm TINYINT(1);
    
    SELECT id INTO perm_id FROM permissions WHERE code = p_permission_code LIMIT 1;
    
    IF perm_id IS NULL THEN
        RETURN 0;
    END IF;
    
    
    IF EXISTS(
        SELECT 1 FROM user_permissions up
        WHERE up.user_id = p_user_id 
            AND up.permission_id = perm_id
            AND up.permission_type = 'deny'
            AND (up.expires_at IS NULL OR up.expires_at > NOW())
    ) THEN
        RETURN 0;
    END IF;
    
    
    SET has_perm = (SELECT COUNT(*) > 0
        FROM user_roles ur
        JOIN role_permissions rp ON ur.role_id = rp.role_id
        WHERE ur.user_id = p_user_id AND rp.permission_id = perm_id);
    
    IF has_perm THEN
        RETURN 1;
    END IF;
    
    
    SET has_perm = (SELECT COUNT(*) > 0
        FROM user_permissions up
        WHERE up.user_id = p_user_id 
            AND up.permission_id = perm_id
            AND up.permission_type IN ('grant', 'override')
            AND (up.expires_at IS NULL OR up.expires_at > NOW()));
    
    RETURN IF(has_perm, 1, 0);
END$$

CREATE DEFINER=`root`@`localhost` FUNCTION `generate_student_number` (`class_code` VARCHAR(10), `admission_year` YEAR) RETURNS VARCHAR(20) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci DETERMINISTIC BEGIN
DECLARE next_number INT;
SELECT COALESCE(
    MAX(
      CAST(
        SUBSTRING_INDEX(admission_no, '/', -1) AS UNSIGNED
      )
    ),
    0
  ) + 1 INTO next_number
FROM students
WHERE admission_no LIKE CONCAT(class_code, '/', admission_year, '/%');
RETURN CONCAT(
  class_code,
  '/',
  admission_year,
  '/',
  LPAD(next_number, 4, '0')
);
END$$

DELIMITER ;

