--
-- Triggers `conduct_tracking`
--
DELIMITER $$
CREATE TRIGGER `trg_log_conduct_recording` AFTER INSERT ON `conduct_tracking` FOR EACH ROW BEGIN
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'conduct_recorded',
    JSON_OBJECT(
      'student_id',
      NEW.student_id,
      'term_id',
      NEW.term_id,
      'conduct_rating',
      NEW.conduct_rating
    ),
    NOW()
  );
END
$$
DELIMITER ;

