--
-- Table structure for table `parents`
--

CREATE TABLE `parents` (
  `id` int(10) UNSIGNED NOT NULL,
  `first_name` varchar(50) NOT NULL,
  `middle_name` varchar(50) DEFAULT NULL,
  `last_name` varchar(50) NOT NULL,
  `id_number` varchar(30) DEFAULT NULL COMMENT 'National ID/Passport Number',
  `gender` enum('male','female','other') NOT NULL,
  `date_of_birth` date DEFAULT NULL COMMENT 'Parent date of birth',
  `phone_1` varchar(20) NOT NULL,
  `phone_2` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `occupation` varchar(100) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `status` enum('active','inactive') NOT NULL DEFAULT 'active',
  `portal_password` varchar(255) DEFAULT NULL COMMENT 'Hashed password for parent portal login',
  `portal_status` enum('active','inactive','suspended') NOT NULL DEFAULT 'active' COMMENT 'Parent portal account status',
  `portal_last_login` datetime DEFAULT NULL COMMENT 'Timestamp of last successful portal login',
  `portal_password_reset_token` varchar(64) DEFAULT NULL COMMENT 'One-time token for portal password reset',
  `portal_password_reset_expires` datetime DEFAULT NULL COMMENT 'Expiry for the portal password reset token',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

