--
-- Triggers `portfolios`
--
DELIMITER $$
CREATE TRIGGER `trg_create_portfolio_on_promotion` AFTER INSERT ON `portfolios` FOR EACH ROW BEGIN IF NEW.status = 'active' THEN
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'portfolio_created',
    JSON_OBJECT(
      'portfolio_id',
      NEW.id,
      'student_id',
      NEW.student_id,
      'year',
      NEW.academic_year
    ),
    NOW()
  );
END IF;
END
$$
DELIMITER ;

