--
-- Triggers `students`
--
DELIMITER $$
CREATE TRIGGER `trg_create_student_obligations` AFTER INSERT ON `students` FOR EACH ROW BEGIN
    DECLARE v_academic_year INT;
    DECLARE v_level_id INT;
    
    
    SELECT id INTO v_academic_year
    FROM academic_years
    WHERE is_current = 1
    LIMIT 1;
    
    
    SELECT c.level_id INTO v_level_id
    FROM class_streams cs
    JOIN classes c ON cs.class_id = c.id
    WHERE cs.id = NEW.stream_id;
    
    
    INSERT INTO student_fee_obligations (
        student_id,
        academic_year,
        term_id,
        fee_structure_detail_id,
        amount_due,
        amount_paid,
        status,
        due_date,
        created_at
    )
    SELECT 
        NEW.id as student_id,
        fsd.academic_year,
        fsd.term_id,
        fsd.id as fee_structure_detail_id,
        fsd.amount as amount_due,
        0 as amount_paid,
        'pending' as status,
        COALESCE(fsd.due_date, 
            CASE 
                WHEN at.term_number = 1 THEN CONCAT(at.year, '-02-15')
                WHEN at.term_number = 2 THEN CONCAT(at.year, '-05-15')
                WHEN at.term_number = 3 THEN CONCAT(at.year, '-09-15')
            END
        ) as due_date,
        NOW()
    FROM fee_structures_detailed fsd
    JOIN academic_terms at ON fsd.term_id = at.id
    WHERE fsd.level_id = v_level_id
      AND fsd.student_type_id = NEW.student_type_id
      AND fsd.academic_year = v_academic_year
      AND fsd.status = 'active';
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_emit_student_status_event` AFTER UPDATE ON `students` FOR EACH ROW BEGIN IF NEW.status != OLD.status THEN
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'student_status_changed',
    JSON_OBJECT(
      'student_id',
      NEW.id,
      'old_status',
      OLD.status,
      'new_status',
      NEW.status
    ),
    NOW()
  );
END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_update_class_capacity` AFTER INSERT ON `students` FOR EACH ROW BEGIN
UPDATE class_streams cs
SET current_students = (
    SELECT COUNT(*)
    FROM students s
    WHERE s.stream_id = cs.id
  )
WHERE cs.id = NEW.stream_id;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_update_student_status` AFTER UPDATE ON `students` FOR EACH ROW BEGIN IF NEW.status IN ('graduated', 'transferred')
  AND OLD.status != NEW.status THEN
INSERT INTO notifications (
    user_id,
    type,
    title,
    message,
    priority,
    created_at
  )
VALUES (
    get_parent_user_id(NEW.id),
    'info',
    'Student Status Update',
    CONCAT('Your child status changed to ', NEW.status),
    'medium',
    NOW()
  );
END IF;
END
$$
DELIMITER ;

