--
-- Triggers `student_attendance`
--
DELIMITER $$
CREATE TRIGGER `trg_emit_attendance_event` AFTER INSERT ON `student_attendance` FOR EACH ROW BEGIN
INSERT INTO system_events (event_type, event_data, created_at)
VALUES (
    'attendance_marked',
    JSON_OBJECT(
      'student_id',
      NEW.student_id,
      'date',
      NEW.date,
      'status',
      NEW.status,
      'class_id',
      NEW.class_id,
      'term_id',
      NEW.term_id
    ),
    NOW()
  );
END
$$
DELIMITER ;

