DELIMITER $$
CREATE TRIGGER `trg_after_password_change` AFTER UPDATE ON `users` FOR EACH ROW BEGIN
    IF NEW.password != OLD.password THEN
        UPDATE users
        SET password_changed_at = CURRENT_TIMESTAMP
        WHERE id = NEW.id;
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_audit_delete` BEFORE DELETE ON `users` FOR EACH ROW BEGIN
INSERT INTO audit_trail (
    user_id,
    action,
    table_name,
    record_id,
    old_values,
    created_at
  )
VALUES (
    OLD.id,
    'DELETE',
    'users',
    OLD.id,
    JSON_OBJECT(
      'username',
      OLD.username,
      'email',
      OLD.email,
      'role_id',
      OLD.role_id,
      'status',
      OLD.status
    ),
    NOW()
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_audit_insert` AFTER INSERT ON `users` FOR EACH ROW BEGIN
INSERT INTO audit_trail (
    user_id,
    action,
    table_name,
    record_id,
    new_values,
    created_at
  )
VALUES (
    NEW.id,
    'INSERT',
    'users',
    NEW.id,
    JSON_OBJECT(
      'username',
      NEW.username,
      'email',
      NEW.email,
      'role_id',
      NEW.role_id,
      'status',
      NEW.status
    ),
    NOW()
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_audit_update` AFTER UPDATE ON `users` FOR EACH ROW BEGIN
INSERT INTO audit_trail (
    user_id,
    action,
    table_name,
    record_id,
    old_values,
    new_values,
    created_at
  )
VALUES (
    NEW.id,
    'UPDATE',
    'users',
    NEW.id,
    JSON_OBJECT(
      'username',
      OLD.username,
      'email',
      OLD.email,
      'role_id',
      OLD.role_id,
      'status',
      OLD.status
    ),
    JSON_OBJECT(
      'username',
      NEW.username,
      'email',
      NEW.email,
      'role_id',
      NEW.role_id,
      'status',
      NEW.status
    ),
    NOW()
  );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_prevent_user_delete` BEFORE DELETE ON `users` FOR EACH ROW BEGIN
DECLARE role_name VARCHAR(50);
SELECT name INTO role_name
FROM roles
WHERE id = OLD.role_id;
IF role_name = 'admin' THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Cannot delete admin users';
END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_validate_email` BEFORE INSERT ON `users` FOR EACH ROW BEGIN IF NEW.email NOT REGEXP '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+.[A-Za-z]{2,}$' THEN SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT = 'Invalid email format';
END IF;
END
$$
DELIMITER ;

