--
-- Structure for view `vw_active_allocations`
--
DROP TABLE IF EXISTS `vw_active_allocations`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_active_allocations`  AS SELECT `a`.`id` AS `id`, `a`.`allocation_number` AS `allocation_number`, `i`.`name` AS `item_name`, `i`.`code` AS `item_code`, `ic`.`name` AS `category`, `a`.`allocated_quantity` AS `allocated_quantity`, `a`.`returned_quantity` AS `returned_quantity`, `a`.`allocated_quantity`- `a`.`returned_quantity` AS `outstanding_quantity`, `d`.`name` AS `department`, `a`.`allocated_to_event` AS `allocated_to_event`, `c`.`name` AS `class_name`, `a`.`status` AS `status`, `a`.`allocation_date` AS `allocation_date`, `a`.`expected_return_date` AS `expected_return_date`, `s`.`first_name` AS `allocated_by_first`, `s`.`last_name` AS `allocated_by_last`, `a`.`created_at` AS `created_at` FROM (((((`inventory_allocations` `a` left join `inventory_items` `i` on(`a`.`item_id` = `i`.`id`)) left join `inventory_categories` `ic` on(`i`.`category_id` = `ic`.`id`)) left join `inventory_departments` `d` on(`a`.`allocated_to_department_id` = `d`.`id`)) left join `classes` `c` on(`a`.`allocated_to_class_id` = `c`.`id`)) left join `staff` `s` on(`a`.`allocated_by` = `s`.`id`)) WHERE `a`.`status` in ('allocated','issued','partially_returned') ;

-- --------------------------------------------------------

--
-- Structure for view `vw_arrears_summary`
--
DROP TABLE IF EXISTS `vw_arrears_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_arrears_summary`  AS SELECT `sl`.`name` AS `level`, `sl`.`code` AS `level_code`, count(distinct `sa`.`student_id`) AS `students_in_arrears`, sum(`sa`.`total_arrears`) AS `total_arrears_amount`, avg(`sa`.`total_arrears`) AS `average_arrears`, count(distinct case when `sa`.`arrears_status` = 'overdue' then `sa`.`student_id` end) AS `overdue_students`, count(distinct case when `sa`.`days_overdue` > 30 then `sa`.`student_id` end) AS `overdue_more_than_30_days`, count(distinct case when `sa`.`days_overdue` > 60 then `sa`.`student_id` end) AS `overdue_more_than_60_days`, count(distinct case when `asp`.`status` = 'active' then `asp`.`id` end) AS `settlement_plans_active`, sum(case when `asp`.`status` = 'active' then `asp`.`total_amount` else 0 end) AS `amount_on_settlement_plans` FROM (((((`student_arrears` `sa` join `students` `s` on(`sa`.`student_id` = `s`.`id`)) join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) join `classes` `c` on(`cs`.`class_id` = `c`.`id`)) join `school_levels` `sl` on(`c`.`level_id` = `sl`.`id`)) left join `arrears_settlement_plans` `asp` on(`sa`.`id` = `asp`.`arrears_id`)) WHERE `sa`.`academic_year` = year(curdate()) GROUP BY `sl`.`id` ORDER BY `sl`.`name` ASC ;

-- --------------------------------------------------------

--
-- Structure for view `vw_collection_rate_by_class`
--
DROP TABLE IF EXISTS `vw_collection_rate_by_class`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_collection_rate_by_class`  AS SELECT `sl`.`name` AS `level_name`, `sl`.`code` AS `level_code`, `at`.`name` AS `academic_term`, count(distinct `sfo`.`student_id`) AS `total_students`, sum(`sfo`.`amount_due`) AS `total_fees_due`, sum(`sfo`.`amount_paid`) AS `total_fees_paid`, sum(`sfo`.`amount_waived`) AS `total_fees_waived`, round(sum(`sfo`.`amount_paid`) / sum(`sfo`.`amount_due`) * 100,2) AS `collection_rate_percent`, count(distinct case when `sfo`.`status` = 'paid' then `sfo`.`student_id` end) AS `students_paid_in_full`, count(distinct case when `sfo`.`status` = 'partial' then `sfo`.`student_id` end) AS `students_partial_payment`, count(distinct case when `sfo`.`status` = 'pending' then `sfo`.`student_id` end) AS `students_no_payment`, round(avg(`sfo`.`amount_paid`),2) AS `average_payment_per_student` FROM (((((`student_fee_obligations` `sfo` join `students` `s` on(`sfo`.`student_id` = `s`.`id`)) join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) join `classes` `c` on(`cs`.`class_id` = `c`.`id`)) join `school_levels` `sl` on(`c`.`level_id` = `sl`.`id`)) join `academic_terms` `at` on(`sfo`.`term_id` = `at`.`id`)) GROUP BY `sl`.`id`, `at`.`id` ORDER BY `sl`.`name` ASC, `at`.`term_number` ASC ;

-- --------------------------------------------------------

--
-- Structure for view `vw_fee_carryover_summary`
--
DROP TABLE IF EXISTS `vw_fee_carryover_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_fee_carryover_summary`  AS SELECT `sfc`.`student_id` AS `student_id`, `s`.`admission_no` AS `admission_no`, concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`, `cs`.`stream_name` AS `class_name`, `sfc`.`academic_year` AS `academic_year`, `sfc`.`term_id` AS `term_id`, CASE WHEN `sfc`.`term_id` is null THEN 'Academic Year' ELSE concat('Term ',`sfc`.`term_id`) END AS `period_type`, `sfc`.`previous_balance` AS `previous_balance`, `sfc`.`surplus_amount` AS `surplus_amount`, `sfc`.`action_taken` AS `action_taken`, `sfc`.`created_at` AS `created_at`, `sfc`.`notes` AS `notes` FROM ((`student_fee_carryover` `sfc` join `students` `s` on(`sfc`.`student_id` = `s`.`id`)) left join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) ORDER BY `sfc`.`academic_year` DESC, `sfc`.`created_at` DESC ;

