--
-- Structure for view `vw_fee_schedule_by_class`
--
DROP TABLE IF EXISTS `vw_fee_schedule_by_class`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_fee_schedule_by_class`  AS SELECT `sl`.`name` AS `level_name`, `sl`.`code` AS `level_code`, `at`.`name` AS `academic_term`, `st`.`code` AS `student_type`, `st`.`name` AS `student_type_name`, `ft`.`name` AS `fee_name`, `ft`.`category` AS `fee_category`, `fsd`.`amount` AS `amount_due`, `fsd`.`due_date` AS `due_date`, count(distinct `s`.`id`) AS `number_of_students` FROM (((((((`fee_structures_detailed` `fsd` join `school_levels` `sl` on(`fsd`.`level_id` = `sl`.`id`)) join `academic_terms` `at` on(`fsd`.`term_id` = `at`.`id`)) join `student_types` `st` on(`fsd`.`student_type_id` = `st`.`id`)) join `fee_types` `ft` on(`fsd`.`fee_type_id` = `ft`.`id`)) left join `classes` `c` on(`c`.`level_id` = `sl`.`id`)) left join `class_streams` `cs` on(`cs`.`class_id` = `c`.`id`)) left join `students` `s` on(`s`.`stream_id` = `cs`.`id` and `s`.`student_type_id` = `st`.`id`)) WHERE `fsd`.`academic_year` = year(curdate()) GROUP BY `sl`.`id`, `at`.`id`, `st`.`id`, `ft`.`id`, `fsd`.`id` ORDER BY `sl`.`name` ASC, `at`.`term_number` ASC, `st`.`name` ASC, `ft`.`name` ASC ;

