--
-- Structure for view `vw_fee_type_collection`
--
DROP TABLE IF EXISTS `vw_fee_type_collection`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_fee_type_collection`  AS SELECT `ft`.`name` AS `fee_type`, `ft`.`code` AS `fee_code`, `ft`.`category` AS `fee_category`, `ft`.`is_mandatory` AS `is_mandatory`, sum(`sfo`.`amount_due`) AS `total_due`, sum(`sfo`.`amount_paid`) AS `total_collected`, sum(`sfo`.`balance`) AS `total_outstanding`, count(distinct `sfo`.`student_id`) AS `students_affected`, round(sum(`sfo`.`amount_paid`) / sum(`sfo`.`amount_due`) * 100,2) AS `collection_rate_percent`, count(distinct case when `sfo`.`status` = 'paid' then `sfo`.`student_id` end) AS `students_paid`, count(distinct case when `sfo`.`status` = 'partial' then `sfo`.`student_id` end) AS `students_partial`, count(distinct case when `sfo`.`status` = 'pending' then `sfo`.`student_id` end) AS `students_pending` FROM ((`student_fee_obligations` `sfo` join `fee_structures_detailed` `fsd` on(`sfo`.`fee_structure_detail_id` = `fsd`.`id`)) join `fee_types` `ft` on(`fsd`.`fee_type_id` = `ft`.`id`)) WHERE `sfo`.`academic_year` = year(curdate()) GROUP BY `ft`.`id` ORDER BY sum(`sfo`.`amount_due`) DESC ;

