DROP TABLE IF EXISTS `vw_food_consumption_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_food_consumption_summary`  AS SELECT `fc`.`consumption_date` AS `consumption_date`, `i`.`name` AS `food_item`, `i`.`code` AS `code`, `ic`.`name` AS `category`, `fc`.`unit` AS `unit`, sum(`fc`.`quantity_planned`) AS `total_quantity_planned`, sum(`fc`.`quantity_used`) AS `total_quantity_used`, sum(`fc`.`waste_quantity`) AS `total_waste`, sum(`fc`.`total_cost`) AS `total_cost_used`, count(distinct `fc`.`id`) AS `consumption_records`, `s`.`first_name` AS `recorded_by_first`, `s`.`last_name` AS `recorded_by_last` FROM (((`food_consumption_records` `fc` left join `inventory_items` `i` on(`fc`.`inventory_item_id` = `i`.`id`)) left join `inventory_categories` `ic` on(`i`.`category_id` = `ic`.`id`)) left join `staff` `s` on(`fc`.`recorded_by` = `s`.`id`)) GROUP BY `fc`.`consumption_date`, `fc`.`inventory_item_id` ORDER BY `fc`.`consumption_date` DESC ;

