--
-- Structure for view `vw_internal_conversations`
--
DROP TABLE IF EXISTS `vw_internal_conversations`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_internal_conversations`  AS SELECT `c`.`id` AS `conversation_id`, `c`.`title` AS `title`, `c`.`conversation_type` AS `conversation_type`, `c`.`created_by` AS `created_by`, `u`.`first_name` AS `first_name`, `u`.`last_name` AS `last_name`, count(distinct `im`.`id`) AS `total_messages`, max(`im`.`created_at`) AS `last_message_date`, count(distinct case when `im`.`priority` = 'high' then `im`.`id` end) AS `high_priority_messages`, count(`cp`.`id`) AS `participant_count`, `c`.`created_at` AS `created_at`, `c`.`updated_at` AS `updated_at` FROM (((`internal_conversations` `c` left join `users` `u` on(`c`.`created_by` = `u`.`id`)) left join `internal_messages` `im` on(`c`.`id` = `im`.`conversation_id`)) left join `conversation_participants` `cp` on(`c`.`id` = `cp`.`conversation_id`)) GROUP BY `c`.`id` ORDER BY max(`im`.`created_at`) DESC ;

-- --------------------------------------------------------

--
-- Structure for view `vw_inventory_health`
--
DROP TABLE IF EXISTS `vw_inventory_health`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_inventory_health`  AS SELECT `i`.`id` AS `id`, `i`.`name` AS `name`, `i`.`code` AS `code`, `ic`.`name` AS `category`, `i`.`current_quantity` AS `current_quantity`, `i`.`minimum_quantity` AS `minimum_quantity`, `i`.`reorder_level` AS `reorder_level`, CASE WHEN `i`.`current_quantity` = 0 THEN 'OUT OF STOCK' WHEN `i`.`current_quantity` <= `i`.`reorder_level` THEN 'REORDER' WHEN `i`.`current_quantity` <= `i`.`minimum_quantity` THEN 'LOW STOCK' ELSE 'ADEQUATE' END AS `stock_status`, CASE WHEN `i`.`expiry_date` is not null AND `i`.`expiry_date` < curdate() THEN 'EXPIRED' WHEN `i`.`expiry_date` is not null AND `i`.`expiry_date` <= curdate() + interval 30 day THEN 'EXPIRING SOON' ELSE 'OK' END AS `expiry_status`, `i`.`expiry_date` AS `expiry_date`, `i`.`location` AS `location`, `i`.`unit_cost` AS `unit_cost`, `i`.`current_quantity`* `i`.`unit_cost` AS `inventory_value`, `i`.`status` AS `status`, `i`.`updated_at` AS `updated_at` FROM (`inventory_items` `i` left join `inventory_categories` `ic` on(`i`.`category_id` = `ic`.`id`)) ;

-- --------------------------------------------------------

--
-- Structure for view `vw_maintenance_schedule`
--
DROP TABLE IF EXISTS `vw_maintenance_schedule`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_maintenance_schedule`  AS SELECT `em`.`id` AS `id`, `i`.`serial_number` AS `serial_number`, `ii`.`name` AS `equipment_name`, `ii`.`brand` AS `brand`, `ii`.`model` AS `model`, `emt`.`name` AS `maintenance_type`, `em`.`status` AS `status`, `em`.`last_maintenance_date` AS `last_maintenance_date`, `em`.`next_maintenance_date` AS `next_maintenance_date`, to_days(`em`.`next_maintenance_date`) - to_days(curdate()) AS `days_until_due`, CASE WHEN to_days(`em`.`next_maintenance_date`) - to_days(curdate()) <= 0 THEN 'OVERDUE' WHEN to_days(`em`.`next_maintenance_date`) - to_days(curdate()) <= 7 THEN 'DUE SOON' ELSE 'OK' END AS `urgency`, `em`.`notes` AS `notes`, `em`.`created_at` AS `created_at` FROM (((`equipment_maintenance` `em` left join `item_serials` `i` on(`em`.`equipment_id` = `i`.`id`)) left join `inventory_items` `ii` on(`i`.`item_id` = `ii`.`id`)) left join `equipment_maintenance_types` `emt` on(`em`.`maintenance_type_id` = `emt`.`id`)) ORDER BY `em`.`next_maintenance_date` ASC ;

