DROP TABLE IF EXISTS `vw_outstanding_by_class`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_outstanding_by_class`  AS SELECT `sl`.`name` AS `level_name`, `sl`.`code` AS `level_code`, `at`.`name` AS `academic_term`, count(distinct `sfo`.`student_id`) AS `students_with_arrears`, sum(`sfo`.`balance`) AS `total_arrears`, avg(`sfo`.`balance`) AS `average_arrears_per_student`, min(`sfo`.`balance`) AS `minimum_arrears`, max(`sfo`.`balance`) AS `maximum_arrears`, count(distinct case when `sa`.`days_overdue` > 30 then `sa`.`student_id` end) AS `students_overdue_30_days`, count(distinct case when `sa`.`days_overdue` > 60 then `sa`.`student_id` end) AS `students_overdue_60_days` FROM ((((((`student_fee_obligations` `sfo` join `students` `s` on(`sfo`.`student_id` = `s`.`id`)) join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) join `classes` `c` on(`cs`.`class_id` = `c`.`id`)) join `school_levels` `sl` on(`c`.`level_id` = `sl`.`id`)) join `academic_terms` `at` on(`sfo`.`term_id` = `at`.`id`)) left join `student_arrears` `sa` on(`sfo`.`student_id` = `sa`.`student_id` and `sfo`.`academic_year` = `sa`.`academic_year`)) WHERE `sfo`.`status` in ('pending','partial','arrears') GROUP BY `sl`.`id`, `at`.`id` ORDER BY `sl`.`name` ASC, `at`.`term_number` ASC ;

