DROP TABLE IF EXISTS `vw_parent_payment_activity`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_parent_payment_activity`  AS SELECT `p`.`id` AS `parent_id`, concat(`p`.`first_name`,' ',`p`.`last_name`) AS `parent_name`, `p`.`phone_1` AS `contact_number`, count(distinct `pt`.`id`) AS `total_payments`, sum(`pt`.`amount_paid`) AS `total_amount_paid`, count(distinct `pt`.`student_id`) AS `number_of_children`, group_concat(distinct concat(`s`.`first_name`,' ',`s`.`last_name`) separator ', ') AS `children`, max(`pt`.`payment_date`) AS `last_payment_date`, count(distinct case when year(`pt`.`payment_date`) = year(curdate()) then `pt`.`id` end) AS `payments_this_year`, avg(`pt`.`amount_paid`) AS `average_payment` FROM ((`parents` `p` left join `payment_transactions` `pt` on(`p`.`id` = `pt`.`parent_id`)) left join `students` `s` on(`pt`.`student_id` = `s`.`id`)) GROUP BY `p`.`id` ORDER BY sum(`pt`.`amount_paid`) DESC ;

