-- --------------------------------------------------------

--
-- Structure for view `vw_pending_sms`
--
DROP TABLE IF EXISTS `vw_pending_sms`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_pending_sms`  AS SELECT `s`.`id` AS `sms_id`, `s`.`parent_id` AS `parent_id`, concat(`p`.`first_name`,' ',`p`.`last_name`) AS `parent_name`, `s`.`recipient_phone` AS `recipient_phone`, `s`.`message_body` AS `message_body`, `s`.`sms_type` AS `sms_type`, `s`.`status` AS `status`, `ct`.`name` AS `template_name`, `u`.`first_name` AS `sent_by_first`, `u`.`last_name` AS `sent_by_last`, `s`.`created_at` AS `created_at`, `s`.`sent_at` AS `sent_at`, `s`.`delivered_at` AS `delivered_at`, timestampdiff(HOUR,`s`.`created_at`,current_timestamp()) AS `hours_pending` FROM (((`sms_communications` `s` left join `parents` `p` on(`s`.`parent_id` = `p`.`id`)) left join `communication_templates` `ct` on(`s`.`template_id` = `ct`.`id`)) left join `users` `u` on(`s`.`sent_by` = `u`.`id`)) WHERE `s`.`status` in ('pending','queued') ORDER BY `s`.`created_at` ASC ;

