-- --------------------------------------------------------

--
-- Structure for view `vw_sent_emails`
--
DROP TABLE IF EXISTS `vw_sent_emails`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_sent_emails`  AS SELECT `e`.`id` AS `email_id`, `e`.`institution_id` AS `institution_id`, `ei`.`name` AS `institution_name`, `ei`.`contact_person_name` AS `contact_person_name`, `e`.`recipient_email` AS `recipient_email`, `e`.`subject` AS `subject`, `e`.`email_type` AS `email_type`, `e`.`status` AS `status`, count(`e`.`id`) AS `attempts`, max(`e`.`updated_at`) AS `last_attempt`, `u`.`first_name` AS `sent_by_first`, `u`.`last_name` AS `sent_by_last`, `e`.`created_at` AS `created_at`, CASE WHEN `e`.`status` = 'sent' THEN 'Successfully Delivered' WHEN `e`.`status` = 'failed' THEN 'Delivery Failed' WHEN `e`.`status` = 'pending' THEN 'Awaiting Delivery' WHEN `e`.`status` = 'bounced' THEN 'Bounced Back' ELSE 'Unknown' END AS `delivery_status_text` FROM ((`external_emails` `e` left join `external_institutions` `ei` on(`e`.`institution_id` = `ei`.`id`)) left join `users` `u` on(`e`.`sent_by` = `u`.`id`)) GROUP BY `e`.`id` ORDER BY `e`.`created_at` DESC ;

-- --------------------------------------------------------

--
-- Structure for view `vw_sponsored_students_status`
--
DROP TABLE IF EXISTS `vw_sponsored_students_status`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_sponsored_students_status`  AS SELECT `s`.`id` AS `id`, `s`.`admission_no` AS `admission_no`, concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`, `st`.`name` AS `student_type`, `cs`.`stream_name` AS `class_name`, `s`.`is_sponsored` AS `is_sponsored`, `s`.`sponsor_name` AS `sponsor_name`, `s`.`sponsor_type` AS `sponsor_type`, `s`.`sponsor_waiver_percentage` AS `sponsor_waiver_percentage`, coalesce(sum(`sfo`.`amount_due`),0) AS `total_fees_due`, coalesce(sum(`sfo`.`amount_paid`),0) AS `total_paid`, coalesce(sum(`sfo`.`balance`),0) AS `current_balance`, coalesce(sum(`sfo`.`sponsored_waiver_amount`),0) AS `total_waived` FROM (((`students` `s` left join `student_types` `st` on(`s`.`student_type_id` = `st`.`id`)) left join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) left join `student_fee_obligations` `sfo` on(`s`.`id` = `sfo`.`student_id`)) WHERE `s`.`is_sponsored` = 1 GROUP BY `s`.`id`, `st`.`id`, `cs`.`id` ORDER BY `s`.`admission_no` ASC ;

-- --------------------------------------------------------

--
-- Structure for view `vw_student_payment_status`
--
DROP TABLE IF EXISTS `vw_student_payment_status`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_student_payment_status`  AS SELECT `s`.`admission_no` AS `admission_no`, concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`, `sl`.`name` AS `level`, `st`.`name` AS `student_type`, `at`.`name` AS `academic_term`, sum(`sfo`.`amount_due`) AS `total_fees_due`, sum(`sfo`.`amount_paid`) AS `total_fees_paid`, sum(`sfo`.`amount_waived`) AS `total_fees_waived`, sum(`sfo`.`balance`) AS `balance_outstanding`, round(sum(`sfo`.`amount_paid`) / sum(`sfo`.`amount_due`) * 100,2) AS `payment_percentage`, CASE WHEN sum(`sfo`.`balance`) = 0 THEN 'PAID' WHEN sum(`sfo`.`amount_paid`) > 0 THEN 'PARTIAL' ELSE 'PENDING' END AS `payment_status`, max(`pt`.`payment_date`) AS `last_payment_date`, coalesce(count(distinct `pt`.`id`),0) AS `number_of_payments`, coalesce(count(distinct case when `dw`.`discount_type` = 'full_waiver' then `dw`.`id` end),0) AS `waivers_applied`, CASE WHEN `sa`.`arrears_status` = 'overdue' THEN concat('OVERDUE (',`sa`.`days_overdue`,' days)') WHEN `sa`.`arrears_status` = 'current' THEN 'ARREARS' ELSE 'OK' END AS `arrears_status` FROM (((((((((`students` `s` join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) join `classes` `c` on(`cs`.`class_id` = `c`.`id`)) join `school_levels` `sl` on(`c`.`level_id` = `sl`.`id`)) join `student_types` `st` on(`s`.`student_type_id` = `st`.`id`)) left join `student_fee_obligations` `sfo` on(`s`.`id` = `sfo`.`student_id` and `sfo`.`academic_year` = year(curdate()))) left join `academic_terms` `at` on(`sfo`.`term_id` = `at`.`id`)) left join `payment_transactions` `pt` on(`s`.`id` = `pt`.`student_id`)) left join `fee_discounts_waivers` `dw` on(`s`.`id` = `dw`.`student_id`)) left join `student_arrears` `sa` on(`s`.`id` = `sa`.`student_id` and `sa`.`academic_year` = year(curdate()))) WHERE `s`.`status` = 'active' GROUP BY `s`.`id`, `sl`.`id`, `at`.`id` ORDER BY `s`.`admission_no` ASC ;

