--
-- Structure for view `vw_student_payment_status_enhanced`
--
DROP TABLE IF EXISTS `vw_student_payment_status_enhanced`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_student_payment_status_enhanced`  AS SELECT `s`.`id` AS `id`, `s`.`admission_no` AS `admission_no`, concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`, `st`.`name` AS `student_type`, `cs`.`stream_name` AS `class_name`, `cl`.`name` AS `level_name`, year(`sfo`.`created_at`) AS `academic_year`, coalesce(`t`.`term_number`,1) AS `term_number`, coalesce(sum(`sfo`.`amount_due`),0) AS `total_due`, coalesce(sum(`sfo`.`amount_paid`),0) AS `total_paid`, coalesce(sum(`sfo`.`amount_waived`),0) AS `total_waived`, coalesce(sum(`sfo`.`balance`),0) AS `current_balance`, coalesce(max(`sfo`.`year_balance`),0) AS `year_balance`, coalesce(max(`sfo`.`term_balance`),0) AS `term_balance`, coalesce(max(`sfo`.`previous_year_balance`),0) AS `previous_year_balance`, coalesce(max(`sfo`.`previous_term_balance`),0) AS `previous_term_balance`, `sfo`.`payment_status` AS `payment_status`, `s`.`is_sponsored` AS `is_sponsored`, `s`.`sponsor_waiver_percentage` AS `sponsor_waiver_percentage` FROM (((((`students` `s` left join `student_types` `st` on(`s`.`student_type_id` = `st`.`id`)) left join `class_streams` `cs` on(`s`.`stream_id` = `cs`.`id`)) left join `classes` `cl` on(`cs`.`class_id` = `cl`.`id`)) left join `student_fee_obligations` `sfo` on(`s`.`id` = `sfo`.`student_id`)) left join `academic_terms` `t` on(`sfo`.`term_id` = `t`.`id`)) GROUP BY `s`.`id`, `sfo`.`academic_year`, `sfo`.`term_id`, `sfo`.`payment_status` ORDER BY `s`.`admission_no` ASC, year(`sfo`.`created_at`) DESC, coalesce(`t`.`term_number`,1) DESC ;

