-- Structure for view `vw_unread_announcements`
--
DROP TABLE IF EXISTS `vw_unread_announcements`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_unread_announcements`  AS SELECT `a`.`id` AS `announcement_id`, `a`.`title` AS `title`, `a`.`content` AS `content`, `a`.`priority` AS `priority`, `a`.`target_audience` AS `target_audience`, `u`.`first_name` AS `published_by_first`, `u`.`last_name` AS `published_by_last`, `a`.`status` AS `status`, `a`.`created_at` AS `created_at`, `a`.`updated_at` AS `updated_at`, count(`av`.`id`) AS `total_views` FROM (((`announcements_bulletin` `a` left join `staff` `st` on(`a`.`published_by` = `st`.`id`)) left join `users` `u` on(`st`.`user_id` = `u`.`id`)) left join `announcement_views` `av` on(`a`.`id` = `av`.`announcement_id`)) WHERE `a`.`status` = 'published' GROUP BY `a`.`id` ORDER BY `a`.`created_at` DESC ;

