DROP TABLE IF EXISTS `vw_upcoming_class_schedules`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_upcoming_class_schedules`  AS SELECT `cs`.`id` AS `id`, `cs`.`class_id` AS `class_id`, `c`.`name` AS `class_name`, `cs`.`day_of_week` AS `day_of_week`, `cs`.`start_time` AS `start_time`, `cs`.`end_time` AS `end_time`, `cs`.`period_number` AS `period_number`, `cs`.`subject_id` AS `subject_id`, coalesce(`cu`.`name`,'') AS `subject_name`, `cs`.`teacher_id` AS `teacher_id`, concat(`s`.`first_name`,' ',`s`.`last_name`) AS `teacher_name`, `cs`.`room_id` AS `room_id`, `r`.`name` AS `room_name`, `cs`.`academic_year_id` AS `academic_year_id`, `cs`.`term_id` AS `term_id`, `cs`.`status` AS `status` FROM ((((`class_schedules` `cs` join `classes` `c` on(`cs`.`class_id` = `c`.`id`)) left join `curriculum_units` `cu` on(`cs`.`subject_id` = `cu`.`id`)) left join `staff` `s` on(`cs`.`teacher_id` = `s`.`id`)) left join `rooms` `r` on(`cs`.`room_id` = `r`.`id`)) WHERE `cs`.`status` = 'active' ;

