--
-- Structure for view `vw_upcoming_exam_schedules`
--
DROP TABLE IF EXISTS `vw_upcoming_exam_schedules`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_upcoming_exam_schedules`  AS SELECT `es`.`id` AS `id`, `es`.`term_id` AS `term_id`, `es`.`academic_year_id` AS `academic_year_id`, `es`.`class_id` AS `class_id`, `c`.`name` AS `class_name`, `es`.`subject_id` AS `subject_id`, coalesce(`cu`.`name`,'') AS `subject_name`, `es`.`exam_name` AS `exam_name`, `es`.`exam_type` AS `exam_type`, `es`.`exam_date` AS `exam_date`, `es`.`start_time` AS `start_time`, `es`.`end_time` AS `end_time`, `es`.`duration_minutes` AS `duration_minutes`, `es`.`room_id` AS `room_id`, `r`.`name` AS `room_name`, `es`.`venue` AS `venue`, `es`.`invigilator_id` AS `invigilator_id`, concat(`inv`.`first_name`,' ',`inv`.`last_name`) AS `invigilator_name`, `es`.`supervisor_id` AS `supervisor_id`, concat(`sup`.`first_name`,' ',`sup`.`last_name`) AS `supervisor_name`, `es`.`notes` AS `notes`, `es`.`status` AS `status` FROM (((((`exam_schedules` `es` join `classes` `c` on(`es`.`class_id` = `c`.`id`)) left join `curriculum_units` `cu` on(`es`.`subject_id` = `cu`.`id`)) left join `rooms` `r` on(`es`.`room_id` = `r`.`id`)) left join `staff` `inv` on(`es`.`invigilator_id` = `inv`.`id`)) left join `staff` `sup` on(`es`.`supervisor_id` = `sup`.`id`)) WHERE `es`.`status` in ('scheduled','upcoming','in_progress') ;

